INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('active_pipeline_experiment_key', '', 'experiments', 'Experiment key the content pipeline routes through (matches experiments.key in the experiments table). Empty = disabled. Set via `poindexter settings set active_pipeline_experiment_key <key>` to opt the pipeline into an A/B experiment. The harness is best-effort — a misconfigured experiment never halts the pipeline, just falls back to default config.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('alert_force_telegram_event_types', '', 'alerts', 'Comma-separated list of event_type (or alertname) values that always route to Telegram regardless of severity. Use for alerts like ''cost_guard_tripped,worker_crashed_unrecoverable'' that the operator wants on their phone even at warning severity. Empty default = no overrides; pure severity routing applies (critical/error -> both, warning/info -> Discord only). Glad-Labs/poindexter#420.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('alertmanager_url', 'http://alertmanager:9093', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('alert_repeat_summarize_threshold_minutes', '30', 'alerts', 'After a fingerprint has been firing continuously for this many minutes (now - first_seen_at), the dispatcher escalates to an AI summary that counts repeats, lists time-correlated other alerts in the same window, and produces a paragraph diagnosis. One-shot per fingerprint (marked via summary_dispatched_at). Default 30 min. Glad-Labs/poindexter#420.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('alert_repeat_suppress_window_minutes', '120', 'alerts', 'When a brain alert with the same fingerprint (source|severity|normalized_message) last fired inside this window, the new fire is counted (repeat_count++) but NOT dispatched. Default 30 = the same alert at most every 30 min until escalation. Set to 0 to disable dedup entirely (every fire dispatches). Glad-Labs/poindexter#420. [bumped 2026-05-20 from 30 to 120 per finding #499]', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('allowed_origins', '', 'cors', 'Comma-separated allowed CORS origins', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('alt_text_budget', '120', 'content', 'Character budget for inline <img alt="..."> text. The alt generator produces complete sentences within this budget; over-budget drafts are re-summarised or fall back to a topic-based template — never mid-word truncated. Ref: GH-84.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('api_base_url', 'http://worker:8002', 'identity', 'Backend API base URL', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('api_url', 'http://localhost:8002', 'general', 'Backend API base URL (legacy alias for api_base_url)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_gate_topic_decision_reject_status', 'dismissed', 'general', 'Status set on pipeline_tasks when a topic-decision gate rejects the topic (vs. the global default ''rejected''). Distinct so dashboards can separate rejected drafts from dismissed topics.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_ttl_days', '7', 'pipeline', 'Days before unapproved posts are auto-expired', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('app_version', '3.0.1', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('atom_runs_capture_enabled', 'true', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('audio_gen_engine', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('auto_append_sources_section', 'true', 'content', 'Auto-append ## Sources at finalize if missing', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('auto_publish_threshold', '0', 'pipeline', 'Quality score threshold for auto-publishing (0=disabled)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_daily_enabled', 'true', 'backup', 'When false, the backup-daily container takes no dumps.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_daily_interval', '24h', 'backup', 'Cadence between daily dumps.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_daily_retention', '7', 'backup', 'Number of daily dumps to keep.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_hourly_enabled', 'true', 'backup', 'When false, the backup-hourly container takes no dumps. Loop keeps running so toggling back on is instant.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_hourly_interval', '1h', 'backup', 'Cadence between hourly dumps. Format: <N>{s|m|h|d}. Read fresh each tick — no restart needed.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_hourly_retention', '24', 'backup', 'Number of hourly dumps to keep. Older dumps are pruned after each successful run.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_backup_dir', '/host-backups/auto', 'backup', 'Host path the backup containers bind-mount their dumps into. Override when POINDEXTER_BACKUP_DIR points somewhere non-default (e.g. a second drive).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_daily_max_age_hours', '26', 'backup', 'Daily tier staleness threshold (mirrors the compose healthcheck slack of 90 min beyond the 24 h cadence).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_enabled', 'true', 'backup', 'Master switch for the brain backup-watcher probe (#388). When false, the probe short-circuits without stat-ing dumps or restarting containers.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_hourly_max_age_minutes', '90', 'backup', 'Hourly tier staleness threshold. Matches the compose healthcheck so the watcher fires at the same instant the container is marked unhealthy.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_max_retries', '2', 'backup', 'Consecutive `docker restart` attempts before the watcher gives up and lets the dispatcher page the operator. Cumulative across cycles.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_poll_interval_minutes', '5', 'backup', 'Cadence at which the watcher re-checks backup freshness. Matches the brain cycle by default; bump higher only if the brain is overloaded.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_retry_delay_seconds', '120', 'backup', 'How long the watcher waits after `docker restart` before re-stat-ing the dump directory. Long enough for postgres reconnect + initial pg_dump to complete on the operator''s machine.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_sentinel_dir', '/host-backup-logs', 'backup', 'Container path the brain bind-mounts ~/.poindexter/logs into (read-only). brain/backup_watcher.py scans this directory each cycle for dr-backup-*-failed.sentinel files dropped by the host-side dr-backup scripts and surfaces any it finds via alert_events. Set to a path that does NOT exist (e.g. ''/disabled'') to short-circuit the sentinel scan without disabling the rest of the probe (Glad-Labs/poindexter#444).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('brain_anomaly_baseline_window_days', '30', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('brain_anomaly_current_window_hours', '24', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('brain_auto_cancel_grace_minutes', '10', 'pipeline', 'Extra grace period the brain daemon adds on top of stale_task_timeout_minutes before flipping a stuck task to failed. Second line of defence against missed heartbeats during long single-shot GPU calls. Ref: GH-90.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('branch_drift_dedup_hours', '6', 'monitoring', 'Re-page interval (hours) for an unchanged branch-drift state. Dedup is keyed on (repo, local HEAD, origin/main SHA); a new commit on either side re-pages immediately.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('branch_drift_git_dir', '/host-git', 'monitoring', 'git --git-dir path inside the brain container for reading the running checkout''s HEAD. Matches the read-only ./.git:/host-git:ro mount in docker-compose.local.yml.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('branch_drift_poll_interval_minutes', '15', 'monitoring', 'Internal cadence gate (minutes) for the branch-drift canary''s GitHub round-trip. The probe is dispatched every brain cycle (~5 min) but does real work only this often.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('branch_drift_probe_enabled', 'true', 'monitoring', 'Master switch for the brain branch-drift deploy canary (#942). When true, the brain pages the operator if the bind-mounted prod checkout falls behind origin/main.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('branch_drift_repo', 'Glad-Labs/glad-labs-stack', 'monitoring', 'owner/name of the source-of-truth repo the branch-drift canary compares against. Paired with the gh_token secret for private-repo access.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('brand_keywords', '', 'general', 'Comma-separated brand-relevance keywords used by topic_discovery to filter discovered topics to the site''s niche. Empty value falls back to the hardcoded Glad Labs niche set (AI / PC hardware / gaming) for backwards compatibility. Customers running Poindexter for a different niche (e.g. gardening, dentistry) should set this to their own comma-separated list of niche keywords — single-word entries are matched at word boundaries, multi-word / hyphenated entries match as substrings. Case-insensitive. Example: ''gardening,compost,heirloom tomato''.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cadence_slo_enabled', 'true', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cadence_slo_expected_posts_per_day', '1', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cadence_slo_shortfall_ratio', '0.5', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cadence_slo_window_hours', '24', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cli_post_approve_bulk_max_count', '100', 'cli', 'Hard ceiling for matched-post count in a single ''poindexter post approve --no-dry-run --filter ...'' invocation. Refuses to execute when the filter matches more than this many posts unless the operator passes --max=N (still subject to this ceiling). Tighten in production; loosen for backfills.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cli_post_approve_bulk_require_confirm', 'true', 'cli', 'When true, ''poindexter post approve --filter ... --no-dry-run'' always prompts y/N before approving — even if --yes was passed. Belt-and-suspenders for the no-bulk-publish rule. Flip to false only for fully scripted environments where the call site has its own approval gate.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cli_post_create_idempotency_enabled', 'true', 'cli', 'Master switch for `poindexter post create` idempotency (#338). When ''true'', a second invocation with the same computed key inside the window returns the existing post id instead of inserting a duplicate. Set ''false'' to restore the legacy ''every invocation inserts'' behavior.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cli_post_create_idempotency_strategy', 'slug_or_content_hash', 'cli', 'Reserved for future variants of the `poindexter post create` (#338) idempotency-key derivation. Today only ''slug_or_content_hash'' is implemented (slug if explicit, else sha256 of topic+media+gates+operator). Listed here so the knob exists in app_settings before the next strategy lands.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cli_post_create_idempotency_window_minutes', '30', 'cli', 'Dedup window for `poindexter post create` (#338). A second invocation with the same idempotency key WITHIN this many minutes returns the existing post id. Outside the window the command creates a fresh post — protects fat-finger doubles while still allowing a legitimate re-creation of the same topic days later.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cloud_api_daily_limit', '5', 'models', 'Max cloud API calls per day in emergency mode (hard cap)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cloud_api_mode', 'emergency_only', 'models', 'Cloud API usage mode: disabled, emergency_only, fallback, always', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cloudflare_account_id', '', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cloudflare_analytics_api_token', '', 'cloudflare', 'Cloudflare API token scoped to Account Analytics Read. Consumed by the sync_cloudflare_analytics job. Operator fills in via `poindexter settings set cloudflare_analytics_api_token <token> --secret` after deploying the Worker.', true, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cloudflare_analytics_last_sync', '1970-01-01T00:00:00Z', 'cloudflare', 'High-water mark (ISO-8601 UTC) for the sync_cloudflare_analytics job. Advanced atomically after each successful batch insert. Seeded to the epoch so the first run pulls the configured lookback window (default 24h).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cloudinary_cloud_name', '', 'integration', 'Cloudinary cloud name', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('code_density_check_enabled', 'true', 'content', 'GH-234: enable the code-block density quality gate. When true, tech-tagged posts that ship without enough fenced code blocks emit a (non-blocking) warning during multi_model_qa review.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('code_density_long_post_floor_words', '300', 'content', 'GH-234: prose word-count threshold above which the line-ratio sub-check kicks in. Per the issue spec, short posts (<300 words) don''t get the ratio check because a 200-word note doesn''t need a code-heavy layout to be valuable.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('code_density_min_blocks_per_700w', '1', 'content', 'GH-234: minimum fenced code blocks expected per 700 prose words in a tech post. The check skips posts under 200 prose words regardless. Set to 0 to disable just this sub-check.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('code_density_min_line_ratio_pct', '20', 'content', 'GH-234: minimum percentage of non-empty content lines that must live inside a fenced code block, applied only to posts above code_density_long_post_floor_words. Set to 0 to disable just this sub-check.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('code_density_tag_filter', 'technical,ai,programming,ml,python,javascript,rust,go', 'content', 'GH-234: comma-separated list of tag/topic tokens that qualify a post as ''tech'' for the code-block density rule. Matched case-insensitively against post tags + topic. Set to an empty string to disable the gate without touching the master flag.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_age_months', '6', 'identity', 'Company age in months (update periodically)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_founded_date', '2025-09-25', 'identity', 'Company founding date', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_founded_year', '2025', 'identity', 'Company founding year', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_founder_name', 'Matt', 'identity', 'Founder name', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_name', 'Glad Labs', 'identity', 'Legal company name', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_products', '', 'identity', 'Known real products (for hallucination checks)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_team_size', '1', 'identity', 'Team size for content validation', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('compose_drift_auto_recover_enabled', 'true', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('compose_drift_skip_services', '', 'monitoring', 'Comma-separated list of compose service names the brain drift probe (#213) should skip. Useful for services with intentional spec drift (a sidecar hot-patched in place, a manually-edited container the operator doesn''t want to recreate). Empty by default — every service with a container_name in compose gets checked.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('compose_project_name', 'glad-labs-website', 'infrastructure', 'Docker Compose project name used by compose drift auto-recover', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('compose_spec_path', '/app/docker-compose.local.yml', 'monitoring', 'Path to the docker-compose.yml the brain compose-drift probe (#213) reads. The brain container bind-mounts the host''s ./docker-compose.local.yml into this path read-only. Change this if your stack ships its compose file at a different path (e.g. /app/docker-compose.yml for the default-name variant). Setting an unreadable path degrades the probe to a structured ''unknown'' status without crashing the brain.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_flow_max_concurrency', '3', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_max_refinement_attempts', '3', 'content', 'Max attempts to refine content quality', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_min_word_count', '800', 'content', 'Minimum word count for blog posts', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_quality_minimum', '75', 'pipeline', 'Minimum quality score to even queue for approval. Below this = auto-reject.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_router_contradiction_review_max_tokens', '1500', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_router_contradiction_revise_max_tokens', '8000', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_router_contradiction_timeout_seconds', '120', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_router_qa_rewrite_max_tokens', '8000', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_router_qa_rewrite_timeout_seconds', '240', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_router_seo_title_max_tokens', '4000', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_target_word_count', '1500', 'content', 'Target word count for blog posts', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_temperature', '0.7', 'tokens', 'Temperature for content generation', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_validator_warning_qa_penalty', '3', 'quality', 'Points subtracted from final QA score per validator warning (GH-91)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_validator_warning_reject_threshold', '5', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_weekly_cap', '50', 'pipeline', 'Maximum new posts per week (0=unlimited). Topic discovery respects this.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cost_alert_threshold_pct', '80', 'cost', 'Alert when spend exceeds this % of limit', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cost_tier.budget.model', 'ollama/gemma-4-31B-it-qat:latest', 'llm_routing', 'Model resolved when callers pass cost_tier=budget. Quantized 27B; offline retention work.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cost_tier.free.model', 'ollama/qwen3:8b', 'llm_routing', 'Model resolved when callers pass cost_tier=free. Smallest local; image-decision tier.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cost_tier.premium.model', 'anthropic/claude-haiku-4-5', 'llm_routing', 'Model resolved when callers pass cost_tier=premium. Cloud cross-model QA; cost_guard-gated.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cost_tier.standard.model', 'ollama/glm-4.7-5090:latest', 'llm_routing', 'Model resolved when callers pass cost_tier=standard. Default writer + critic.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('daily_budget_usd', '1.00', 'pipeline', 'Daily LLM spend budget in USD (ignored if cloud_api_mode=disabled)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('daily_post_limit', '4', 'pipeline', 'Maximum posts to generate per day', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('daily_spend_limit', '1.00', 'cost', 'Hard cap on daily AI spend in USD', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('daily_spend_limit_usd', '2.0', 'cost', 'Maximum daily AI spend in USD (read by services/cost_guard.py)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('database_pool_max_size', '20', 'general', 'Max DB pool connections', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('database_pool_min_size', '5', 'general', 'Min DB pool connections', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('deepeval_enabled', 'true', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('deepeval_g_eval_criterion', 'The output is well-grounded in the input topic, internally consistent across paragraphs, and does not invent specific facts, names, statistics, or quotes that lack support.', 'qa', 'Criterion text the DeepEval g-eval judge model uses to grade the post. Operators can rewrite this to emphasize different axes (brand voice, tone, technical accuracy) without a code change. Keep it concise — the judge derives its own step-by-step rubric from this single sentence.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('deepeval_judge_model', 'ollama/glm-4.7-5090:latest', 'qa', 'LLM model identifier used by the DeepEval g-eval and faithfulness reviewers. Default ''glm-4.7-5090'' (Matt''s local thinking model — free at the point of use). Operators on cloud OpenAI-compat keys can override to e.g. ''gpt-4o-mini'' for a stronger second opinion. Routed through DeepEval''s standard provider configuration.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('deepeval_threshold_faithfulness', '0.8', 'qa', 'Threshold (0–1) above which the DeepEval faithfulness reviewer marks the post as approved. Default 0.8 — at least 80%% of claims must be attributable to a chunk of the research bundle the writer was given. Posts that don''t have research_sources skip the metric entirely.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('deepeval_threshold_g_eval', '0.7', 'qa', 'Threshold (0–1) above which the DeepEval g-eval reviewer marks the post as approved. Default 0.7 — anything below means the judge model thinks the post is weakly grounded against the criterion. Edit deepeval_g_eval_criterion to retune what ''good'' means without a code change.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('default_media_to_generate', '', 'general', 'Comma-separated list of media to generate alongside each new post when --media isn''t passed. Empty = blog post only. Canonical names: podcast, video, short.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('default_model_tier', 'budget', 'pipeline', 'Default model cost tier (free/budget/standard/premium/flagship)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('default_ollama_model', 'auto', 'content', 'Default Ollama model for LLM calls. "auto" → OllamaClient picks the first available pulled model. Override with a specific model tag (e.g. "gemma4:31b").', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('default_template_slug', 'canonical_blog', 'pipeline', 'Lane C cutover switch: when set, every new pipeline_tasks row without an explicit caller-supplied template_slug gets this value. Empty (default) preserves the legacy chunked StageRunner flow inside content_router_service. Set to ''canonical_blog'' to route every new task through services/template_runner.py + the LangGraph canonical_blog template (Glad-Labs/poindexter#355). Per-task overrides (e.g. dev_diary cron passing template_slug=''dev_diary'' explicitly) always win.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('default_workflow_gates', 'topic,draft,final', 'general', 'Comma-separated gate sequence applied to new posts when --gates isn''t passed. Empty string = fully autonomous (no human checkpoints). Canonical names: topic, draft, podcast, video, short, final.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('dev_diary_auto_publish_dry_run', 'false', 'publishing', 'When true (default), auto-publish gate runs in observe-only mode: logs ''would have auto-published Y/N'' for each finalize but never actually approves. Set to false ONLY after the dry-run logs show consistent agreement with operator manual approves over multiple runs.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('dev_diary_auto_publish_max_edit_distance', '50', 'publishing', 'Char-level edit distance threshold for the ''clean run'' criterion. Default 50 — trivial typo fixes pass; substantive rewording fails. Tune based on observed published_post_edit_metrics.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('dev_diary_auto_publish_min_clean_runs', '3', 'publishing', 'Trailing N publishes that must have edit_distance < auto_publish_max_edit_distance for the gate to fire. Default 3 — stricter than 1 to avoid one-good-run bias.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('dev_diary_auto_publish_threshold', '70', 'publishing', 'Quality_score floor for dev_diary auto-publish. Default -1 disables the gate entirely. Set to a value 0-100 (e.g. 85) to opt into auto-publish for runs scoring at or above the floor. ALSO requires dev_diary_auto_publish_dry_run=false.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('dev_diary_last_run_date', '2026-06-06', 'scheduling', 'YYYY-MM-DD (UTC) of the last successful dev-diary job run. Idempotency marker — the job no-ops if this matches today.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('development_mode', 'false', 'general', 'Enable development mode', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('devto_api_base', 'https://dev.to/api', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('devto_min_reactions', '20', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('devto_per_page', '15', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('devto_tag', '', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('devto_top_days', '7', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('disable_auth_for_dev', 'true', 'general', 'Disable auth in development', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('discord_bot_probe_dedup_hours', '1', 'brain', 'Minimum hours between repeat alert_events writes while the Discord bot returns 401/403. Default 1h — one page per hour while broken.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('discord_bot_probe_enabled', 'true', 'brain', 'Master switch for brain/discord_bot_probe.py (poindexter#435). When false, the probe is skipped entirely.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('discord_bot_probe_interval_minutes', '5', 'brain', 'Minutes between real Discord /users/@me round-trips. Probe is dispatched every brain cycle but skips inside the interval.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('discord_bot_probe_timeout_seconds', '5', 'brain', 'httpx timeout for the Discord /users/@me round-trip.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('discord_ops_channel_id', '', 'identity', 'Discord channel for ops notifications', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_poll_interval_minutes', '5', 'monitoring', 'Cadence at which the brain runs the port-forward probe. Default 5 min matches the brain cycle so it runs every cycle.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_probe_enabled', 'true', 'monitoring', 'Master switch for the brain Docker port-forward stuck-state probe (#222). When false the probe short-circuits without scanning containers.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_probe_timeout_seconds', '3', 'monitoring', 'Per-HTTP-probe timeout in seconds. Kept tight (3s) so a stuck service can''t block the brain cycle on probes.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_recovery_wait_seconds', '45', 'monitoring', 'How long the probe waits after a docker restart before re-probing to confirm recovery. Default 5s lets Docker Desktop re-establish the wslrelay forward.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_restart_cap_per_window', '3', 'monitoring', 'Maximum number of times a single container may be restarted within the rolling window. Prevents runaway restart loops when the underlying issue is not actually a stuck port forward.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_restart_cap_window_minutes', '60', 'monitoring', 'Rolling window length in minutes for the per-container restart cap. Default 60 min — combined with the cap of 3 means at most 3 restarts of any one container per hour.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_watch_list', '[{"container": "poindexter-pyroscope", "port": 4040, "path": "/"}, {"container": "poindexter-glitchtip-web", "port": 8080, "path": "/"}, {"container": "poindexter-alertmanager", "port": 9093, "path": "/-/healthy"}, {"container": "poindexter-pgadmin", "port": 80, "host_port": 18443, "path": "/misc/ping"}, {"container": "poindexter-grafana", "port": 3000, "path": "/api/health"}, {"container": "poindexter-prometheus", "port": 9090, "path": "/-/healthy", "host_port": 9091}, {"container": "poindexter-loki", "port": 3100, "path": "/ready"}, {"container": "poindexter-langfuse-web", "port": 3000, "host_port": 3010, "path": "/api/public/health"}, {"container": "poindexter-clickhouse", "port": 8123, "path": "/ping"}, {"container": "poindexter-minio", "port": 9000, "path": "/minio/health/live"}, {"container": "poindexter-redis-insight", "port": 5540, "path": "/healthcheck"}, {"container": "poindexter-pyroscope-grafana-frontend", "port": 4045, "path": "/"}]', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('electricity_rate_kwh', '0.2579', 'cost', 'RI Energy Last Resort Service rate $0.14770/kWh (verified by Matt)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_age_days', '14', 'memory', 'Days before raw embeddings get clustered + summarized into a single is_summary=TRUE row by CollapseOldEmbeddingsJob. Set to <21 (claude_sessions TTL) so collapse runs BEFORE TTL pruning hard-deletes the originals.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_cluster_size', '8', 'memory', 'GH-81: target cluster count per (source_table, age-group) when the collapse job runs k-means over candidate embeddings. The effective k is min(cluster_size, candidate_count // 2) so small groups fall back to fewer clusters. 8 gives ~8x reduction on a typical ~64-row group.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_enabled', 'true', 'memory', 'GH-81: master switch for the embeddings collapse job. When true, the scheduled job clusters old rows per source_table, writes one summary row per cluster, and deletes the originals. Defaults to false so existing deployments are unaffected until an operator opts in.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_source_tables', 'claude_sessions,brain,audit', 'memory', 'GH-81: comma-separated list of source_table values the collapse job is allowed to touch. posts/issues/memory are deliberately NOT in this list — they''re queried by the live pipeline and must retain raw embeddings. Operators may add/remove entries but should never include an authoritative source here.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_summary_model', 'ollama/gemma-4-31B-it-qat:latest', 'memory_compression', 'Ollama model used for cluster-summary generation. Picked empirically: factually dense, no thinking-trace overhead, ~12s/5-excerpt cluster on the RTX 5090. Override via app_settings if a smaller/larger model fits the operator''s GPU bandwidth better.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_summary_provider', 'ollama', 'memory_compression', 'Summarization backend for CollapseOldEmbeddingsJob. ''ollama'' calls the local LLM to produce a real summary; ''joined_preview'' falls back to the legacy joined-text heuristic (used when ollama is unreachable, also a no-LLM-cost mode). Defaults to ''ollama'' as of migration 0127.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_summary_timeout_seconds', '60', 'memory_compression', 'Per-call timeout for the LLM summary generation. 60s allows headroom over the ~12s typical run; on timeout the cluster falls back to joined-preview rather than failing the whole collapse pass.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_model', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.audit', '90', 'general', 'Days to keep audit_log embeddings before prune_stale_embeddings drops them. 90d covers the typical operator post-mortem window.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.brain', '365', 'general', 'Days to keep brain_knowledge embeddings before prune. Brain memory is designed to compound; long horizon by design.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.claude_sessions', '21', 'general', 'Days to keep Claude Code session embeddings before prune_stale_embeddings drops them. 21d balances semantic-search recency against keeping enough history for cross-session recall.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.issues', '', 'general', 'Empty = no TTL. Issue embeddings are never auto-pruned — irreplaceable pipeline state.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.memory', '', 'general', 'Empty = no TTL. Memory embeddings are never auto-pruned — operator''s curated state.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.posts', '', 'general', 'Empty = no TTL. Post embeddings are never auto-pruned — feed live RAG retrieval.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embed_model', 'nomic-embed-text', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enabled_topic_sources', 'knowledge,codebase,hackernews,devto,web_search', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_featured_image', 'true', 'image', 'Generate/search featured images for posts', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_mcp_server', 'true', 'features', 'Enable Model Context Protocol server', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_memory_system', 'true', 'features', 'Enable agent memory system', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_pyroscope', 'true', 'observability', 'When true, services/profiling.py:setup_pyroscope() configures the pyroscope-io agent at worker / brain / voice-agent startup so each process ships CPU profiles to the Pyroscope server at pyroscope_server_url (default http://pyroscope:4040). Default flipped to true in Glad-Labs/poindexter#406. Set to false to disable continuous profiling fleet-wide without rebuilding any images — the agent picks up the change on next service restart.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_sdxl_warmup', 'true', 'general', 'Warm up SDXL models on startup', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_tracing', 'true', 'observability', 'Master switch for OpenTelemetry tracing. When true, services.tracing.setup_tracing initializes the TracerProvider + OTLP gRPC exporter and instruments FastAPI for HTTP request spans. Lifespan-time read; toggle requires worker restart.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_training_capture', 'true', 'features', 'Enable training data capture from pipeline runs', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_writer_self_review', 'true', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('environment', 'development', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('finance_poll_interval_seconds', '3600', 'finance', 'Expected Mercury poll cadence in seconds (matches PollMercuryJob hourly schedule). Staleness window = this × finance_poll_stale_multiplier.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('finance_poll_stale_multiplier', '3', 'finance', 'How many missed poll intervals to tolerate before the finance brain probe pages. Window = finance_poll_interval_seconds × this (default 3 × 1h = 3h).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('findings_alert_route_watermark', '76339', 'plugin_telemetry', 'Highest audit_log.id forwarded to alert_events by FindingsAlertRouterJob. Pre-seeded 2026-05-15 to current max to skip 7-day historical backlog of un-routed criticals.', false, true) ON CONFLICT (key) DO NOTHING;
