INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_auto_expire_batch_size', '50', 'gates', 'Cap per-cycle expiry to this many gates to avoid huge batches. Excess rolls over to the next cycle.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_auto_expire_enabled', 'true', 'gates', 'Master switch for the brain gate auto-expire probe (#338). When false, the probe short-circuits without scanning gates.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_auto_expire_notify_threshold', '1', 'gates', 'Only ping the operator (Telegram coalesced) when batch size >= this. Default 1 = always notify on any expiry.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gh_repo', 'Glad-Labs/glad-labs-stack', 'integrations', 'GitHub repository (``owner/name``) the dev_diary topic source queries for merged PRs and notable commits when assembling the daily build-in-public context bundle. Read by services/topic_sources/dev_diary_source.py via direct GitHub REST API calls (``GET /repos/{repo}/pulls`` + ``GET /repos/{repo}/commits``). Pair with the ``gh_token`` secret for authenticated rate limits + private-repo access. Defaults to the Glad Labs operator monorepo; OSS operators on the public Poindexter distribution should point this at their own repo. Closes Glad-Labs/poindexter#405.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_api_token', '', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_base_url', 'http://glitchtip-web:8000', 'monitoring', 'Base URL for the GlitchTip API the brain triage probe queries. Default is the compose-internal hostname; brain.docker_utils.localize_url() rewrites it to host.docker.internal:8080 when the brain runs on the host. Override only if you''re running GlitchTip outside the default poindexter compose stack.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_triage_alert_freshness_hours', '24', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_triage_alert_threshold_count', '10', 'monitoring', 'Brain triage probe pages via notify_operator() when a GlitchTip issue has count >= this AND matches no entry in glitchtip_triage_auto_resolve_patterns. Default 10 surfaces novel recurring errors as a Telegram/Discord page before they pile up unseen. Per-issue dedupe by id within a single brain process uptime — restart the brain to re-page. Bump higher if the pager gets too chatty.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_triage_auto_resolve_patterns', '[{"title_pattern": "Error while fetching prompt .* \\[Errno 111\\] Connection refused", "action": "resolve", "reason": "Langfuse transient unreachable"}, {"title_pattern": "(ConnectError|ConnectTimeout|gaierror).*name resolution", "action": "resolve", "max_count": 20, "reason": "Docker/upstream DNS flap"}, {"title_pattern": "^ReadTimeout$", "action": "resolve", "max_count": 10, "reason": "Single-shot ollama/HN timeout"}, {"title_pattern": "^CancelledError$", "action": "resolve", "reason": "Scheduler shutdown propagation"}, {"title_pattern": "discord_post: HTTP 429", "action": "resolve", "reason": "Rate-limited, retry-after handles it"}, {"title_pattern": "\\[GH-90\\] finalize_task ABORTED:", "action": "resolve", "reason": "Expected race-abort, should be INFO not ERROR"}, {"title_pattern": "PermissionError.*alertmanager\\.yml", "action": "resolve", "reason": "Stale pre-#524 EACCES on alertmanager.yml; render job now atomic-writes worker-owned config (verified ok=True 2026-05-31). A real recurrence also surfaces in the worker render-job log + doctor."}]', 'monitoring', 'JSONB array of triage rules for the brain GlitchTip probe. Each entry: {title_pattern: <regex>, action: ''resolve'' or ''ignore'', reason: <text>, max_count: <int|null>, level_in: [<level>...] | null}. Default rules derived from the 2026-05-01 audit of 506 open issues — Langfuse exporter spam, ANSI-decorated structlog duplicates, decorative banner lines, per-task update failures, stale cofounder_agent imports, and AllModelsFailedError (ignore-only since the model-router and Ollama probes already cover it). Edit this setting to add tenant-specific rules without code changes.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_triage_default_resolve_max_count', '50', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_triage_enabled', 'true', 'monitoring', 'Master enable for the brain GlitchTip triage probe. When ''true'' (default), the probe runs every cycle (5-min), pulls open issues, auto-resolves matches against glitchtip_triage_auto_resolve_patterns, and pages on novel high-count issues. Set to ''false'' to silence it (e.g. while GlitchTip itself is being upgraded).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_triage_org_slug', 'glad-labs', 'monitoring', 'GlitchTip organization slug the brain triage probe queries. Default ''glad-labs'' matches the org the bootstrap installer creates. Change this if you renamed the org in the GlitchTip UI.', false, true) ON CONFLICT (key) DO NOTHING;
