INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gpu_temperature_high_threshold_c', '85', 'monitoring', 'GPU core temperature (C) above which the brain `gpu_temperature` probe alerts. RTX 5090 hard-throttles around 90C; 85 is the operator-alert threshold. Tunable to taste.', false, true) ON CONFLICT (key) DO NOTHING;
