INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('grafana_alert_folder_uid', 'cfl5ofidejh8ge', 'monitoring', 'Grafana folder UID under which brain alert_sync pushes alert rules. Per-install — get yours from the folder URL in Grafana UI: /dashboards/f/<UID>/...', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('grafana_alert_sync_enabled', 'true', 'monitoring', 'Master switch for the brain daemon''s Grafana alert sync loop. Set to ''false'' to disable the loop entirely without removing rules. Ref: GH-28.', false, true) ON CONFLICT (key) DO NOTHING;
