INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('grafana_api_base_url', 'http://poindexter-grafana:3000', 'monitoring', 'Grafana base URL the brain daemon uses to push alert rules and contact points. Defaults to the docker-compose service name, reachable from the brain container. Override for externally-hosted Grafana. Ref: GH-28.', false, true) ON CONFLICT (key) DO NOTHING;
