INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('guardrails_competitor_list', 'Jasper, Copy.ai, Writesonic, Article Forge, Frase, Surfer SEO, Anyword, Rytr, Outranking, Scalenut, MarketMuse, ContentBot, AutoBlogging, Wordtune, QuillBot', 'qa', 'Comma-separated list of competitor brand names to flag if they appear in a post body (case-insensitive, word-boundary match). Empty string = no enforcement (the gate skips entirely). Operator seeds the list once — every post thereafter gets the check for free.', false, true) ON CONFLICT (key) DO NOTHING;
