INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('image_styles', '[
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('indexnow_ping_url', 'https://api.indexnow.org/indexnow', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('inline_image_prompt_model', 'llama3:latest', 'model_roles', 'Ollama model used to craft SDXL prompts for inline images in blog posts', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('internal_api_base_url', 'http://localhost:8002', 'general', 'Base URL for the internal worker API (used for self-calls like the podcast feed regen)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('langfuse_host', 'http://langfuse-web:3000', 'observability', 'Langfuse base URL for prompt management + tracing. Default empty = Langfuse disabled, prompts resolve via DB+YAML fallback. Set to e.g. http://localhost:3010 (local container) or your Langfuse Cloud URL to enable. UnifiedPromptManager picks up the change on the next worker restart.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('langfuse_tracing_enabled', 'true', 'observability', 'When true (default), LiteLLMProvider registers Langfuse as a success/failure callback so every LLM call emits a span to the Langfuse host configured via langfuse_host + langfuse_public_key + langfuse_secret_key (migration 0153). Set to false to disable tracing without affecting Langfuse prompt management — useful if the Langfuse stack is unhealthy and you don''t want LLM calls paying the failed-callback latency cost. Note: the Langfuse Python SDK already batches + retries spans and never blocks the calling LLM request, so this kill switch is mostly defensive.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('local_database_url', 'postgresql://poindexter:poindexter-brain-local@postgres-local:5432/poindexter_brain', 'system', 'Local brain DB connection string (Docker internal)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('local_llm_api_url', 'http://host.docker.internal:11434', 'content', 'Ollama API base URL for local LLM calls (e.g. http://localhost:11434). Empty value means ''Ollama not configured'' — callers must handle that explicitly per the no-silent-defaults rule. Ref: GH-175.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('local_llm_model_name', 'auto', 'content', 'Ollama model fallback used by agents/content_agent/config when no per-task model is configured. ''auto'' lets OllamaClient pick the first available pulled model. Override with a specific tag (e.g. ''gemma4:31b''). Ref: GH-175.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('mastodon_instance_url', '', 'social', 'GH-36: Full Mastodon instance URL, e.g. ''https://mastodon.social''. Empty = Mastodon distribution skipped.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('max_approval_queue', '100', 'pipeline', 'Restored 2026-04-24 after backlog cleared', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('max_log_backup_count', '3', 'logging', 'Number of rotated log backups to retain. Default 3 matches the historical env-var fallback. Ref: GH-175.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('max_log_size_mb', '5', 'logging', 'Maximum size in MB of a rotating log file before it''s rolled over. Default 5 MB matches the historical env-var fallback. Ref: GH-175.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('max_posts_per_day', '8', 'pipeline', 'Maximum posts to publish per day', false, true) ON CONFLICT (key) DO NOTHING;
