INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('mcp_http_probe_base_url', 'http://host.docker.internal:8004', 'brain', 'Base URL of the Poindexter MCP HTTP server. Probe appends the discovery path. Default http://127.0.0.1:8004.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('mcp_http_probe_dedup_hours', '1', 'brain', 'Minimum hours between repeat alert_events writes while the MCP server stays unreachable. Default 1h.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('mcp_http_probe_discovery_path', '/healthz', 'brain', 'Discovery endpoint path the probe GETs. Returns 200 when the MCP server is alive.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('mcp_http_probe_enabled', 'true', 'brain', 'Master switch for brain/mcp_http_probe.py (poindexter#434).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('mcp_http_probe_interval_minutes', '5', 'brain', 'Minutes between real probe round-trips. Default 5.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('mcp_http_probe_launcher_path', '', 'brain', 'Absolute path to a launcher script (.cmd on Windows, .sh on POSIX) that restarts the MCP HTTP server. Empty (default) = detection only, no auto-recovery. Fire-and-forget; the next cadence cycle decides whether the restart worked.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('mcp_http_probe_restart_cap_per_window', '3', 'brain', 'Max launcher invocations within the rolling restart window. Prevents busy-loop when the underlying problem is persistent.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('mcp_http_probe_restart_window_minutes', '60', 'brain', 'Rolling-window minutes for the restart cap above. Default 60.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('mcp_http_probe_timeout_seconds', '3', 'brain', 'httpx timeout for the localhost probe. Default 3.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('media_approval_discord_notify_enabled', 'true', 'general', 'Master switch — when true, a Discord ops ping fires when a newly-generated podcast/video/short lands in media_approvals with status=pending and the Layer 1 quality eval completes. Defaults to enabled; set to ''false'' to silence the channel.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('media_upload_delay_seconds', '240', 'general', 'Wait this many seconds after a post publishes before uploading podcast/video/short to the object-store CDN', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('memory_compression_excerpts_per_bucket', '12', 'memory_compression', 'How many sample rows feed the LLM prompt and land in the {event_type}_excerpts JSONB column for each day-bucket. 12 is a balance between prompt size and giving the model enough context to write a useful summary.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('memory_compression_summary_model', 'ollama/gemma-4-31B-it-qat:latest', 'memory_compression', 'Ollama model used by retention.summarize_to_table for the per-day summary paragraph. Same default as embedding_collapse_summary_model for consistency — a single model swap covers both compression paths.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('memory_compression_summary_timeout_seconds', '60', 'memory_compression', 'Per-call timeout (seconds) for the LLM summary generation in retention.summarize_to_table. On timeout the handler falls back to a joined-preview summary so a slow LLM doesn''t kill the whole retention pass.', false, true) ON CONFLICT (key) DO NOTHING;
