INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('model_role_critic', 'ollama/gemma4:31b', 'model_roles', 'Best at: quality scoring, detecting issues, structured JSON output. Shootout score: 96 standalone.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('model_role_factchecker', 'ollama/gemma4:31b', 'model_roles', 'Best at: factual accuracy, catching hallucinated claims, conservative reviewer. Different training data from writer.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('model_role_image_decision', 'ollama/phi4:14b', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('model_role_image_prompt', 'ollama/qwen3:8b', 'model_roles', 'Best at: generating SDXL prompts, visual descriptions. Fast.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('model_role_seo', 'ollama/qwen3:8b', 'model_roles', 'Best at: concise output, title generation, keyword extraction. Fast for metadata tasks.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('model_role_summarizer', 'ollama/phi3:latest', 'model_roles', 'Best at: fast summaries, social media copy, short-form content. Lightweight.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('model_role_writer', 'ollama/glm-4.7-5090:latest', 'model_roles', 'Best at: long-form content, structured output, follows instructions. Shootout score: 96 in hybrid config.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('monthly_spend_limit', '20.00', 'cost', 'Hard cap on monthly AI spend in USD', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('monthly_spend_limit_usd', '10.0', 'cost', 'Maximum monthly AI spend in USD (read by services/cost_guard.py)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('morning_brief_enabled', 'true', 'monitoring', 'Master switch for the morning_brief scheduled job. When false the job short-circuits and never queries Postgres.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('morning_brief_hour_local', '7', 'monitoring', 'Local-time hour the morning_brief job fires (informational; the active schedule lives in the Job class cron expression). Surfaced here so an operator dashboard can show the configured hour.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('morning_brief_lookback_hours', '24', 'monitoring', 'Lookback window in hours used to roll up published posts, awaiting_approval entries, failed tasks, alert counts, costs, and brain probe activity.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('morning_brief_telegram_critical_only', 'true', 'monitoring', 'When true the brief only pings Telegram on critical-severity alerts or failed tasks (Discord still always receives the full brief). Set false to also ping Telegram on quiet mornings.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_batch_delay_seconds', '2', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_batch_size', '50', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_email', '', 'general', 'Newsletter sender email (legacy)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_enabled', 'true', 'newsletter', 'Enable newsletter sending on publish', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_from_email', '', 'identity', 'Newsletter sender address', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_from_name', 'Glad Labs', 'newsletter', 'Newsletter sender display name', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_provider', 'resend', 'newsletter', 'Email provider: resend or smtp', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_batch_expires_days', '7', 'niche_pivot', 'Number of days a topic_batch row stays open before its expires_at watermark trips. Default 7 matches the prior hardcoded timedelta(days=7) in TopicBatchService._write_batch. Higher = give the operator more time to rank/resolve a batch; lower = force timely operator action.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_carry_forward_decay_factor', '0.7', 'niche_pivot', 'Multiplicative decay applied to a candidate''s decay_factor each time it survives a batch unpicked. Default 0.7 matches the prior hardcoded literal in TopicBatchService._load_carry_forward — by the third batch a candidate has decayed to 0.7^3 = 0.343 of its original score. Lower = more aggressive (older candidates fall off the rank list faster); higher = stickier (the same topic keeps resurfacing for many batches).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_embedding_model', 'nomic-embed-text', 'niche_pivot', 'Ollama embedding model used for niche topic ranking and writer-mode RAG snippet retrieval. Default ''nomic-embed-text'' matches the prior hardcoded literal in topic_ranking.py (_embed_text_cached). Override with another locally-pulled embedding model (must produce 768-dim vectors to match embeddings.embedding column type).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_goal_descriptions', '{"TRAFFIC": "Topic likely to attract organic search traffic; trending keyword, broad appeal, evergreen demand.", "EDUCATION": "Topic that teaches the reader something concrete and useful they didn''t know before.", "BRAND": "Topic that reinforces the operator''s positioning and unique perspective.", "AUTHORITY": "Topic that demonstrates the operator''s depth and expertise on something specific.", "REVENUE": "Topic that drives a commercial outcome: signups, sales, conversions, paid feature awareness.", "COMMUNITY": "Topic that resonates with the operator''s existing audience; sparks discussion, shares, replies.", "NICHE_DEPTH": "Topic that goes deep on the operator''s niche specialty rather than broad-audience content."}', 'niche_pivot', 'JSON blob mapping each goal_type (TRAFFIC, EDUCATION, BRAND, AUTHORITY, REVENUE, COMMUNITY, NICHE_DEPTH) to the prose anchor used to compute its goal vector embedding. Operators tune the prose to nudge what each goal weight ''means'' for their niche. Follow-up: extract to a dedicated niche_goal_prompts (niche_id, goal_type) table so each operator can override per-niche; current single-blob shape is a system-wide override that mirrors the prior dict constant in topic_ranking.py.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_internal_rag_per_kind_limit', '4', 'niche_pivot', 'Per-source-kind limit passed to InternalRagSource.generate by TopicBatchService._discover_internal. Default 4 matches the prior hardcoded literal — pulls 4 most-recent items from each of {claude_session, brain_knowledge, audit_event, decision_log, memory_file, post_history} per discovery sweep. Higher = larger candidate pool, more LLM tokens spent on distillation; lower = faster sweep, cheaper.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_internal_rag_snippet_max_chars', '600', 'niche_pivot', 'Per-snippet character cap when joining raw snippets into the topic/angle distillation prompt in InternalRagSource._distill_topic_angle. Default 600 matches the prior hardcoded slice (s[:600]). Higher = more context per snippet, larger prompt; lower = tighter prompt, faster + cheaper distillation.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_ollama_chat_timeout_seconds', '300', 'niche_pivot', 'HTTP timeout (seconds) for direct Ollama /api/chat calls made by topic_ranking._ollama_chat_json — used by the LLM scorer, internal RAG distillation, story_spine outline pass, and two_pass revise pass. Default 60 matches the prior hardcoded httpx timeout. Higher = tolerate slower local models; lower = fail fast on a wedged Ollama.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_top_n_per_pool', '5', 'niche_pivot', 'Top N candidates per pool (external + internal) carried forward from the embedding pre-rank into the LLM final-score stage. Default 5 matches the prior hardcoded slice in TopicBatchService._embed_and_pre_rank and run_sweep (top10 = pool_external[:5] + pool_internal[:5]). Higher = wider LLM prompt, more candidates to rank; lower = tighter shortlist, cheaper LLM call.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('nvidia_exporter_url', 'http://poindexter-gpu-exporter:9835/metrics', 'general', 'nvidia-smi metrics exporter', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('oauth_issuer_url', '', 'security', 'Public-facing issuer URL advertised in RFC 8414 metadata. Falls back to request.url when empty (e.g. localhost dev).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_base_url', 'http://host.docker.internal:11434', 'general', 'Ollama API endpoint', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_client_timeout_seconds', '1500', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_concurrency_limit', '10', 'performance', 'Maximum concurrent in-flight Ollama requests this worker process will issue — passed to aiolimiter.AsyncLimiter. Prevents bursts of pipeline tasks from VRAM-thrashing the GPU and silently falling back to a smaller model. Tune down on shared GPUs, up on a dedicated rig. Live changes apply via services.ollama_client.rebuild_concurrency_limiter() or a worker restart.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_electricity_cost_per_1k_tokens', '0.000256', 'cost', 'Ollama electricity cost per 1K tokens (USD)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_max_retries', '3', 'performance', 'Maximum number of attempts (initial + retries) for Ollama generate_with_retry. Passed to tenacity''s stop_after_attempt. Default 3 = 1 try + 2 retries. Lower this if you''d rather fail-fast to the cloud fallback chain; raise it on a flaky local Ollama.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_num_ctx', '8192', 'gpu', 'Ollama context window size — limits KV cache VRAM usage', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_retry_initial_seconds', '1', 'performance', 'Initial backoff delay (seconds) for Ollama retries — passed to tenacity''s wait_exponential_jitter(initial). Doubles on each subsequent retry up to ollama_retry_max_seconds, with up to 2s jitter.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_retry_max_seconds', '30', 'performance', 'Upper bound (seconds) on Ollama retry backoff — passed to tenacity''s wait_exponential_jitter(max). Caps the exponential growth so a long retry chain can''t stretch into multi-minute waits.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('openclaw_gateway_url', 'http://localhost:18789', 'general', 'OpenClaw gateway URL', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('openclaw_webhook_url', '', 'webhooks', 'OpenClaw webhook delivery URL', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('operator_id', 'operator', 'general', 'Default operator ID', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('operator_url_probe_skip_keys', 'gitea_url,google_sitemap_ping_url,indexnow_ping_url,mcp_http_probe_base_url,oauth_issuer_url,openclaw_gateway_url,preview_base_url,public_site_revalidate_url,r2_public_url,sdxl_server_url,social_linkedin_url,social_x_url,storage_public_url,voice_agent_ollama_url,voice_agent_public_join_url', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('operator_url_probe_target_overrides', '{"video_server_url": {"method": "HEAD", "reason": "poindexter-wan-server has no root index — bare HEAD/GET / returns 404. Real callers POST to /generate; service-alive means the host answers at all. 5xx + network errors stay real.", "alive_codes": "200-499"}, "indexnow_ping_url": {"method": "HEAD", "reason": "IndexNow ping is POST-only with a JSON payload. Bare HEAD/GET returns 4xx; 5xx + network errors stay real.", "alive_codes": "200-499"}, "storage_public_url": {"method": "HEAD", "reason": "Cloudflare R2 public-bucket base URL. Bucket has no / index — bare HEAD returns 404. We POST/PUT to path-prefixed URLs under it; the bucket itself is alive whenever the host answers at all. 5xx + DNS errors stay real.", "alive_codes": "200-499"}, "google_sitemap_ping_url": {"method": "HEAD", "reason": "Google sitemap submission endpoint is POST-only with ''?sitemap=URL'' query param. Bare HEAD/GET returns 405 or 400; that means Google is alive, just refusing the wrong request shape. 5xx + network errors stay real.", "alive_codes": "200-499"}, "voice_agent_stt_base_url": {"probe_url": "http://speaches:8000/health", "method": "GET", "reason": "speaches /v1 is the OpenAI-compat base path with no GET handler; /health is the liveness endpoint (returns 200)"}, "voice_agent_tts_base_url": {"probe_url": "http://speaches:8000/health", "method": "GET", "reason": "speaches /v1 is the OpenAI-compat base path with no GET handler; /health is the liveness endpoint (returns 200)"}, "voice_agent_claude_code_host_brain_url": {"probe_url": "http://host.docker.internal:8123/healthz", "method": "GET", "reason": "voice_brain_host /turn is POST-only with bearer auth; /healthz is the dedicated GET health check"}}', 'observability', 'Per-URL probe behavior overrides for the operator-url probe. JSON map keyed by app_setting key (e.g. ''google_sitemap_ping_url''). Each value specifies alive_codes (HTTP codes counted as ''service alive'', default ''200-399''), method (probe method, default HEAD), and reason (why the override exists — operator documentation). Use this to mark outbound-only APIs (sitemap pings, public-bucket URLs, etc.) where 4xx responses mean ''host alive, request shape wrong'' rather than ''service down''. Without an override the global default (200-399 = alive) applies. Per Glad-Labs/glad-labs-stack#347 no-silencing rule: this is the visible alternative to the muted skip-list approach.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_cache_ttl_seconds', '3600', 'firefighter', 'TTL (seconds) for the POST /api/triage process-local idempotency cache (#347 step 3). Repeat calls for the same alert_event_id within this window return the cached diagnosis instead of re-invoking the LLM. Set lower while iterating on the system prompt to force re-calls; set higher to absorb brain retry storms without budget impact.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_enabled', 'true', 'firefighter', 'Master kill-switch for the firefighter ops LLM (#347). When false, alert_dispatcher skips the parallel triage task and operators only see the raw alert. Flip without redeploy.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_max_context_tokens', '4000', 'firefighter', 'Cap on the pre-fetched context size handed to the LLM. When the assembled context (alert + history + audit_log + pipeline_tasks + app_settings snapshot) would exceed this, firefighter_service truncates oldest audit_log rows first. Rough 4-chars-per-token approximation. #347.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_max_diagnosis_tokens', '400', 'firefighter', 'Cap on the diagnosis output length (Telegram-friendly). The service truncates with a ''[...]'' marker if the LLM exceeds this. Rough 4-chars-per-token approximation. #347.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_model_class', 'ops_triage', 'firefighter', 'model_router tier the firefighter_service uses for triage (#347). Defaults to a dedicated ''ops_triage'' class which maps to free / glm-4.7-5090 in the model_router tier table. Change to ''standard'' / ''budget'' / etc. to A/B alternative writers.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_retry_backoff_seconds', '[10, 30, 90]', 'firefighter', 'JSON list of per-attempt sleep durations (seconds) the brain uses between retries when worker /api/triage is unreachable. Length should equal ops_triage_retry_max. #347.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_retry_max', '3', 'firefighter', 'Maximum retry attempts when the brain can''t reach the worker /api/triage endpoint. Retries are scheduled with the backoff from ops_triage_retry_backoff_seconds. #347.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_system_prompt', 'You are the Poindexter operator. The system you are diagnosing is the Poindexter content pipeline -- a self-hosted FastAPI worker, brain daemon, Postgres + pgvector, Ollama for LLM inference. You will be shown an alert + curated database state. Your job is to write ONE SHORT PARAGRAPH (<=400 tokens) explaining: what likely happened, why you think so (cite the rows you saw), and one suggested next step the operator could take. Do NOT propose code changes -- those go to a different escalation path. Do NOT suggest ALL POSSIBLE causes -- commit to your most likely diagnosis. If the context is genuinely ambiguous, say so plainly and stop.', 'firefighter', 'Operator-persona system prompt the triage LLM sees. Iterable without redeploy. Keep <=400 tokens; the prompt sets the voice (one paragraph, commit to most-likely diagnosis, no code suggestions). #347.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_writer_model', 'ollama/gemma-4-31B-it-qat:latest', 'ops-triage', 'Local Ollama model used for brain alert triage (the /api/triage endpoint). Defaults to gemma-4-31B-it-qat:latest because thinking-mode models (glm-4.7, qwen3 family) consume their entire token budget on <think> reasoning before emitting any user-facing prose, leaving the operator-facing diagnosis empty. Override only with non-thinking models, OR pair a thinking model with a much larger ops_triage_max_diagnosis_tokens (>2000) so the actual response fits past the thinking trace. Defensive <think> stripping is applied regardless of which model resolves, so a thinking model will not crash the path — but the prose quality is still better with a non-thinking model.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('otel_exporter_otlp_endpoint', 'http://tempo:4318/v1/traces', 'observability', 'OTLP gRPC endpoint that the worker pushes spans to. Default points at the docker-compose tempo service on its OTLP gRPC port. Change to a remote tempo or a collector if needed.', false, true) ON CONFLICT (key) DO NOTHING;
