INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('plugin.topic_source.igdb', '{"enabled": false, "interval_seconds": 21600, "config": {"lookback_days": 14, "limit": 20, "theme_id": 32}}', 'plugins', 'IGDB indie-games topic source. Disabled by default — set Twitch credentials (igdb_twitch_client_id + igdb_twitch_client_secret), then flip enabled=true. Source code: services/topic_sources/igdb.py.', false, true) ON CONFLICT (key) DO NOTHING;
