INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('podcast_cover_url', 'https://pub-1432fdefa18e47ad98f213a8a2bf14d5.r2.dev/podcast/cover.jpg', 'media', 'Square podcast cover art URL for itunes:image element (Apple/Spotify require 1400-3000px)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('podcast_description', 'AI-development audio essays from Glad Labs. Narrated deep-dives on building an autonomous content pipeline, local LLMs, and the solo-founder tech stack.', 'general', 'Podcast RSS description', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('podcast_name', 'Glad Labs Podcast', 'general', 'Podcast title for RSS feeds', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('podcast_script_model', 'ollama/gemma4:31b', 'model_roles', 'Ollama model used to generate podcast scripts from article content', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('podcast_spotify_show_id', '033obxyUXdxhXyQ6erC07G', 'podcast', 'Spotify show ID for the Glad Labs Podcast (the bit after /show/ in the public URL).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('podcast_spotify_url', 'https://open.spotify.com/show/033obxyUXdxhXyQ6erC07G', 'podcast', 'Public Spotify URL for the Glad Labs Podcast. Surface this on the About page and at the bottom of dev_diary posts + in social-poster output when new episodes drop.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('podcast_tts_engine', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prefect_api_base_url', 'http://prefect-server:4200/api', 'brain-probes', 'Where the brain probes hit the Prefect REST API. Defaults to the in-stack compose hostname; docker_utils.localize_url() rewrites localhost to host.docker.internal only when the brain runs inside the container.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prefect_content_flow_concurrency', '3', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prefect_stuck_flow_auto_crash', 'true', 'brain-probes', 'When true, the probe force-CRASHED stuck flow runs via Prefect''s /set_state API so subsequent scheduled dispatches resume immediately. Defaults to false so the operator sees the page before destructive action; flip to true once the threshold is tuned for hands-off recovery.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prefect_stuck_flow_flow_names', 'content_generation', 'brain-probes', 'Comma-separated list of Prefect flow names the stuck-flow probe should watch. Add additional flow names if you spawn separate deployments (e.g. for dev_diary or experiment runs).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prefect_stuck_flow_pending_threshold_minutes', '5', 'brain-probes', 'A flow run that has been PENDING/Submitting longer than this is considered stranded. Captured 2026-05-25: a PENDING run sat 50+ hours and blocked the work pool''s concurrency slot. Typical submit completes in seconds; default 5m is conservative. Tune downward for tighter detection; tune upward only if you ever have legitimately long submit handshakes.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prefect_stuck_flow_probe_enabled', 'true', 'brain-probes', 'Master kill switch for brain/prefect_stuck_flow_probe. Set to false to disable detection of stuck Prefect flow runs (use only if Prefect itself is being rebuilt and the probe would 500 every cycle).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prefect_stuck_flow_queue_depth_threshold', '3', 'brain-probes', 'Brain prefect_stuck_flow_probe: page with a distinct probe.prefect_queue_backlog_detected signal when MORE than this many SCHEDULED runs are overdue (scheduled start in the past). With concurrency=1 an overdue pile-up almost always means the single slot is held by a stuck/PENDING run. Default 3 — a couple of missed cron ticks is noise, a real backlog is several.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prefect_stuck_flow_queue_overdue_min_minutes', '5', 'general', 'Minimum minutes a SCHEDULED Prefect run must be overdue before it counts toward the queue-depth backlog threshold. Prevents false-positive alerts when normal scheduling jitter causes runs to be overdue by 1-2 minutes. Pairs with prefect_stuck_flow_queue_depth_threshold.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prefect_stuck_flow_threshold_minutes', '30', 'brain-probes', 'A content_generation flow run RUNNING longer than this is considered stuck. Default 30m is ~5-6x the typical 5-min duration; tune downward as you build confidence in the probe, tune upward if you ever have legitimately long runs that should not be flagged.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('preferred_ai_video_style', 'flat_vector,isometric,isometric_voxel,line_art,mono_diagram,low_poly,paper_cutout,risograph,pixel_art,glassmorphism,cyberpunk_neon,watercolor,silhouette', 'media', 'Comma-list of stylized AI-video shot styles (drawn from image_styles pool). Director rotates per-shot. Matt 2026-05-28: variety not lock-in.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('preferred_ollama_model', 'gemma-4-31B-it-qat:latest', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('premium_active', 'false', 'experiments', 'When ''true'', UnifiedPromptManager loads prompt_templates rows where source=''premium'' on top of source=''default''. When ''false'' (OSS default), only ''default'' rows load. Set to ''true'' after applying a Glad Labs Premium Prompts pack (Pro tier, delivered via Lemon Squeezy).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('preview_base_url', '', 'notifications', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('privacy_email', '', 'identity', 'Privacy/GDPR contact email', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('probe_webhook_freshness_enabled', 'true', 'monitoring', 'Master switch for the brain''s webhook-freshness probe. When true, the probe checks revenue_events / subscriber_events row freshness on its cycle and notifies the operator if either table has gone quiet beyond its threshold. Disable to silence the alert (e.g. pre-revenue, while you''re still configuring providers).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('probe_webhook_freshness_interval_minutes', '1440', 'monitoring', 'How often the webhook-freshness probe runs (minutes). Default 1440 = once a day. The probe is cheap (two SELECT MAX queries) but the alerts are noisy if it fires hourly — daily catches real outages within a day, which is the right SLA for a passive revenue stream.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prometheus.rule.FinanceMercuryPollStale', '{"enabled": true, "group": "poindexter-business", "interval": "1m", "expr": "absent(poindexter_finance_last_poll_success_timestamp_seconds) or (time() - poindexter_finance_last_poll_success_timestamp_seconds > {threshold.finance_poll_stale_seconds})", "for": "15m", "severity": "warning", "category": "business", "summary": "Mercury finance poll has stalled", "description": "No successful Mercury poll within the configured staleness window (prometheus.threshold.finance_poll_stale_seconds, default 3h = 3\u00d7 the hourly poll). The hourly PollMercuryJob is wedged, the worker is down, or Mercury auth was lost. Check `/api/finance/healthcheck` and `docker logs poindexter-worker`. Tune the window via `poindexter settings set prometheus.threshold.finance_poll_stale_seconds <secs>`."}', 'finance', 'DB-sourced Prometheus alert rule for a stalled Mercury poll (Glad-Labs/poindexter#565). Rendered into rules/*.yml by RenderPrometheusRulesJob. Kept in the DB (not the public DEFAULT_RULES) so the Mercury alert stays in the operator overlay.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prometheus.threshold.daily_spend_critical_usd', '5.0', 'prometheus', 'Daily LLM spend critical threshold', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prometheus.threshold.daily_spend_warning_usd', '4.0', 'prometheus', 'Daily LLM spend warning threshold', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prometheus.threshold.embeddings_stale_seconds', '21600', 'prometheus', 'Seconds without an embeddings_total change before EmbeddingsStale fires', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prometheus.threshold.finance_poll_stale_seconds', '10800', 'finance', 'Prometheus staleness threshold (seconds) for the FinanceMercuryPollStale alert. Default 10800 = 3h. Referenced as {threshold.finance_poll_stale_seconds} in the rule expr; rendered by RenderPrometheusRulesJob.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prometheus.threshold.monthly_spend_warning_usd', '35.0', 'prometheus', 'Monthly spend warning threshold (USD). Includes ALL cost_logs rows — local Ollama electricity (~$30/mo baseline) AND paid API calls. The alert is intended to detect runaway cloud LLM spend, so the threshold sits ~$5 above steady-state to fire only on abnormal usage.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prometheus.threshold.qa_rail_skip_ratio', '1', 'prometheus', 'Per-rail skip ratio that fires QaRailFullySkipped (1 = skipped 100% of the last N QA passes; lower e.g. 0.9 to page earlier) — poindexter#553', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_dedup_hours', '12', 'monitoring', 'Quiet period (in hours) after a stale-PR alert fires before the same PR can re-page. Per-PR dedup is anchored on the fingerprint pr_stale_<repo>_<pr_number> in alert_dedup_state. Default 12 re-pings the operator twice a day if they forgot once.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_max_prs_per_alert', '5', 'monitoring', 'Cap on the number of PRs surfaced in a single Discord-ops message body. Keeps the alert under Discord''s per-message ceiling and stops a runaway backlog from producing an unreadable card. Surplus PRs are summarized as ''and N more''.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_min_hours', '24', 'monitoring', 'Minimum age (in hours) before an open PR is considered stale by the brain PR staleness probe. PRs younger than this are skipped before the per-PR check-runs lookup so the probe doesn''t burn rate-limit budget on fresh work.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_poll_interval_minutes', '60', 'monitoring', 'Internal cadence gate for the brain PR staleness probe. The brain dispatches the probe every cycle (~5 min); the actual GitHub round-trip only fires once per this interval. Default 60 = once an hour.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_probe_enabled', 'true', 'monitoring', 'Master switch for the brain PR staleness probe. When false the probe short-circuits without hitting GitHub. See brain/pr_staleness_probe.py.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_repo', 'Glad-Labs/glad-labs-stack', 'monitoring', 'GitHub repository (``owner/name``) the brain PR staleness probe scans for open PRs. Future-proofs for multi-repo. Pair with the ``gh_token`` secret for authenticated rate limits + private-repo access.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('public_site_revalidate_url', '', 'site', 'Full URL of the Next.js public site''s /api/revalidate endpoint. POSTed by services/revalidation_service.py to bust the ISR cache after every publish. Override per-environment (e.g. point at a Vercel preview URL for staging). Leave blank to fall back to the legacy resolution chain (public_site_url/site_url + /api/revalidate). Glad-Labs/poindexter#327.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('public_site_url', '', 'site', '', false, true) ON CONFLICT (key) DO NOTHING;
