INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('sdxl_enabled', 'true', 'general', 'Master toggle for the SDXL featured/inline image pipeline. When false, source_featured_image skips the SDXL HTTP server and uses Pexels-only. Operators flip to false during SDXL maintenance windows. Read by services/stages/source_featured_image.py (PR #603).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('sdxl_server_url', 'http://host.docker.internal:9836', 'general', 'SDXL image generation server', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('seed_url_fetch_timeout_seconds', '10', 'pipeline', 'URL-based topic seeding: total HTTP timeout (seconds) for the seed_url fetch on POST /api/tasks. Short by design — if a source page takes >10s to respond we''d rather reject the task with a clear 400 than tie up an API worker. Ref: GH-42.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('seed_url_max_bytes', '1048576', 'pipeline', 'URL-based topic seeding: hard cap (bytes) on the decoded response body. Guards against pathological pages that would OOM the API worker before title extraction runs. 1 MiB is plenty for any real article''s <title>/<h1>/<meta>. Ref: GH-42.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('seed_url_user_agent', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36', 'pipeline', 'URL-based topic seeding: User-Agent header for the seed_url fetch. Chrome-ish by default because many news/publisher sites 403 requests-default or urllib UAs. Operators can swap in a branded UA once they''ve set up outbound allowlists. Ref: GH-42.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('self_consistency_enabled', 'true', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('sentry_dsn', 'http://31fbc77a-4ad1-4b9a-8bf9-a13548a8b713@glitchtip-web:8000/1', 'api_keys', 'Sentry DSN for error tracking', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('sentry_enabled', 'true', 'general', 'Enable Sentry error tracking', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('sentry_profiles_sample_rate', '0.1', 'observability', 'Fraction of transactions to capture as CPU profiles. Default 0.1. Same hardcoding bug as traces sample rate.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('sentry_sdk_debug', 'false', 'observability', 'Forces Sentry SDK to log internal debug messages to stderr. Default false — was hardcoded true in dev which flooded logs.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('sentry_traces_sample_rate', '0.1', 'observability', 'Fraction of FastAPI requests sampled as Sentry traces (0.0-1.0). Default 0.1 (10%). Previously hardcoded to 1.0 in dev which produced ~50 DEBUG lines/sec and is suspected contributor to 2026-05-15 00:05 event-loop hang.', false, true) ON CONFLICT (key) DO NOTHING;
