INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_alert_dedup_minutes', '360', 'monitoring', 'Don''t re-fire the same (drive, attribute) alert within this many minutes. Default 360 (6 h) matches the default poll interval — one alert per attribute per cycle, max.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_current_pending_threshold', '0', 'monitoring', 'Inclusive threshold for Current_Pending_Sector. Anything strictly greater fires a warning. 0 = any pending sector at all (recommended — pending sectors precede reallocations).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_drive_filter', '', 'monitoring', 'Optional comma-separated list of drive names (e.g. /dev/sda,/dev/nvme0) to restrict scanning to. Empty = scan everything `smartctl --scan-open` finds.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_enabled', 'true', 'monitoring', 'Master switch for the brain SMART monitor probe (#387). When false, the probe short-circuits without scanning drives.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_poll_interval_hours', '6', 'monitoring', 'Cadence at which the brain runs `smartctl -a` against each detected drive. Default 6h matches typical SMART attribute update cadence.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_power_on_hours_info_threshold', '50000', 'monitoring', 'Power_On_Hours threshold above which the probe emits an info-severity FYI alert. ~50k h = ~5.7 years; useful for replacement-planning, not an emergency.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_reallocated_sector_threshold', '0', 'monitoring', 'Inclusive threshold for Reallocated_Sector_Ct. Anything strictly greater fires a warning alert. 0 = any reallocated sector at all is a warning (most aggressive — recommended).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_smartctl_path', '', 'monitoring', 'Absolute path to the smartctl binary. Empty = use shutil.which("smartctl"). Override when smartmontools is installed somewhere unusual (e.g. C:\Program Files\smartmontools\bin\smartctl.exe).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_wear_leveling_warn_percent', '90', 'monitoring', 'Used-life percentage for SSD Wear_Leveling_Count above which the probe fires a warning. Computed as (100 - normalized_value) for the SMART attribute. Default 90 = warn when only 10% endurance remains.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smtp_host', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smtp_port', '587', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smtp_use_tls', 'true', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('social_distribution_platforms', 'bluesky', 'social', 'GH-36: Comma-separated list of platforms social_poster should push to after a successful publish. Valid values: ''bluesky,mastodon''. Leave empty to disable direct publishing entirely (Telegram/Discord notifications still fire). ''linkedin'', ''reddit'', ''youtube'' are stubs awaiting OAuth — see GH-40.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('social_linkedin_url', '', 'social', 'LinkedIn profile URL', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('social_poster_fallback_model', 'ollama/llama3:latest', 'llm_routing', 'Per-call-site backstop for services.social_poster when cost_tier=''standard'' resolution fails (Lane B batch 2 sweep).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('social_x_handle', '@_gladlabs', 'social', 'X/Twitter handle', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('social_x_url', 'https://x.com/_gladlabs', 'social', 'X/Twitter profile URL', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('stable_audio_open_server_url', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('stage_timeout_draft', '1700', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('staging_mode', 'false', 'pipeline', 'When true, posts go to draft with preview token instead of publishing', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('stale_task_timeout_minutes', '180', 'pipeline', 'Minutes before a running task is considered stale', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('storage_access_key', '98ada7d8c1590c0d90591948da6690a7', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
