INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('structured_extraction_model', 'gemma-4-31B-it-qat:latest', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('support_email', '', 'identity', 'Support contact email', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('task_failure_alert_dedup_window_seconds', '900', 'alerts', 'Suppress duplicate task-failure alerts for the same (task_id, error_message_hash) within this window. Default 900 (15 min). Set to 0 to disable dedup. Per Glad-Labs/poindexter#370.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('task_failure_alert_severity', 'discord', 'alerts', 'Channel routine task-failure alerts route to: ''discord'' (default, the spam channel) or ''telegram'' (escalates to operator''s phone). Per feedback_telegram_vs_discord, Telegram is reserved for the critical-alert list (worker offline, GPU temp, cost overrun, failure-rate breach) — a single bad task should not page the operator. Glad-Labs/poindexter#370.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('task_sweep_interval_seconds', '300', 'pipeline', 'Seconds between stale task sweeps', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_alerts_enabled', 'true', 'notifications', 'Telegram is for severity=critical infra alerts only. Discord receives all routine pipeline events (awaiting approval, published, failed). Set 2026-04-24.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_chat_id', '', 'notifications', 'Telegram chat ID for all alerts', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_cli_audit_logged', 'true', 'integrations', 'When ''true'' (default), every /cli invocation writes one row to the audit_log table (event_type=''telegram_cli_invoked'' or ''telegram_cli_denied'', source=''telegram_cli''). Captures chat_id, the raw command line, exit code, and duration. Disable only for local-dev noise reduction; leave ''true'' in production so you have a forensic trail of every mobile-issued CLI command.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_cli_enabled', 'true', 'integrations', 'Global kill-switch for the Telegram /cli passthrough. When ''true'' (default), ''/cli <args>'' messages from the configured operator chat are routed to the poindexter CLI and the captured output is replied back. When ''false'', /cli messages are ignored (no reply, no audit row). Use this to disable mobile CLI access without redeploying the bot — for example during a sensitive maintenance window.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_cli_max_output_chars', '3500', 'integrations', 'Maximum characters of combined stdout+stderr the Telegram /cli passthrough will reply with. Telegram''s hard per-message limit is 4096; the default 3500 leaves headroom for the ''exit=N duration=Xs'' header line and a ''[output truncated, N more chars]'' marker. Lower this to keep replies short; raise it (up to ~4000) if you need to see more output and don''t mind the bot occasionally hitting the Telegram cap.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_cli_safe_commands', 'post,settings,validators,auth,check_health,get_post_count,health,version', 'integrations', 'Comma-separated allowlist of top-level poindexter CLI subcommands the Telegram /cli passthrough will execute. The first whitespace-separated token after ''/cli'' must match an entry here, otherwise the bot rejects the command with a ''not on allowlist'' message. Default covers the routine ops set: post show/approve/reject, settings get, validators list/enable/disable, auth list-clients, plus a few read-only health checks. Add more entries here as needed (e.g. ''topics'' once you trust the surface).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_cli_timeout_seconds', '30', 'integrations', 'Wall-clock timeout (seconds) for a /cli subprocess. After this many seconds the passthrough kills the process group and replies ''command timed out''. Prevents a slow query (or a hung CLI subcommand) from blocking the bot''s Telegram long-poll loop. Default 30s comfortably covers all read-only CLI commands; bump if you find yourself regularly hitting it on legitimate calls.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('template_runner_progress_streaming', 'true', 'pipeline', 'When on, TemplateRunner emits per-node progress to Discord (NOT Telegram) via notify_operator(critical=False). Default true — Discord is the spam channel by design. Telegram is reserved for critical alerts only (worker offline, GPU temp, cost overrun).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('template_runner_use_postgres_checkpointer', 'true', 'pipeline', 'When true, services/template_runner.py compiles each LangGraph with an AsyncPostgresSaver checkpointer (durable state across worker restarts; resumable by thread_id). When false (default), MemorySaver is used — checkpoints live only for the duration of the run. Phase 1.5 of Glad-Labs/poindexter#371; flip to true after operator review of the smoke + fallback tests.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('thinking_model_substrings', '["qwen3","qwen3.5","glm-4","glm-4.7","deepseek-r1"]', 'llm_routing', 'JSON array of substring needles used by services.llm_providers.thinking_models.is_thinking_model() to classify a model identifier as a thinking-model (one that produces <think>...</think> reasoning blocks). Add a needle to the array when a new thinking-model family lands; remove one to opt a family out of the higher max_tokens budget + /nothink prefix paths.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('title_originality_cache_ttl_hours', '24', 'content', 'GH-87: TTL (hours) for the in-process cache that dedupes repeated DuckDuckGo queries for the same title. DDG rate-limits aggressively, so tightening this below 1h is unwise.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('title_originality_external_check_enabled', 'true', 'content', 'GH-87: enable DuckDuckGo HTML search for the exact post title at approval time. Verbatim external matches subtract title_originality_external_penalty from the QA score.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('title_originality_external_penalty', '-50', 'content', 'GH-87: points subtracted from the QA score when the post title appears verbatim in external search results. Stored as a negative integer for human readability; the service code takes the abs value.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_auto_resolve_enabled', 'true', 'features', 'Master switch for topic_auto_resolve job (poindexter#504 follow-up). When true, the job auto-resolves open topic_batches → content_tasks every 2h, replacing manual poindexter topics rank-batch / resolve-batch operator calls. Safe to disable if you want HITL approval before each topic enters the pipeline.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_auto_resolve_max_per_cycle', '1', 'features', 'Max number of topic_batches the auto-resolver promotes per cycle (every 2h). Default 1 — one new pipeline task every 2h max.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_auto_resolve_niche_cooldown_hours', '12', 'features', 'Minimum hours between auto-resolutions for the same niche. Prevents one niche from monopolizing the pipeline if its batches always have candidates.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_dedup_engine', 'word_overlap', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_dedup_existing_threshold', '0.7', 'pipeline', 'Word-overlap ratio above which a candidate topic is treated as a duplicate of an existing published post or in-flight task. Range 0.0-1.0. Lower = more aggressive filtering. Default 0.7. Was hardcoded 0.4 prior to this fix and was killing 14/14 candidates.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_dedup_intra_batch_threshold', '0.65', 'pipeline', 'Word-overlap ratio above which two candidates from the same scrape batch are treated as duplicates. Range 0.0-1.0. Slightly tighter than vs-existing because a single source dropping near-identical headlines usually IS a dup. Default 0.65.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_auto_enabled', 'true', 'topic_discovery', 'Master kill-switch for the LEGACY auto-firing topic discovery loop in services/idle_worker.py. When ''true'' (default, backward compatible), the loop fires on signals (queue_low, stale_content, rejection_streak) and the 24h safety-net fallback. When ''false'', all auto-firing branches bail out early with an INFO log and no work is queued — operators drive discovery exclusively through the niche-aware operator flow (''poindexter topics rank-batch'' followed by ''poindexter topics resolve-batch''). Manual triggers via topic_discovery_manual_trigger=true still work in either mode so operators can fire one-shot discoveries even with auto disabled. Trade-off: ''true'' keeps the pipeline self-feeding for OSS users with no niches configured, but bypasses the operator approval gate; ''false'' enforces the gate but requires explicit operator action to keep the queue full. See niche-pivot work (#278) and migration 0113 for the operator-driven alternative.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_category_searches', '{}', 'content', 'JSON object mapping category name -> list of keyword search strings. Used by TopicDiscovery._classify_category to bucket a scraped title into a category, and by web-search topic sources to issue DuckDuckGo queries per category. Empty object falls back to the hardcoded Glad Labs categories (technology / startup / security / engineering / insights / business / hardware / gaming) for backwards compatibility. Customers in a different niche should set this to their own category map so classification doesn''t default everything to ''technology''.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_ideation_lookback_days', '30', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_length_distribution', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_manual_trigger', 'false', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_min_cooldown_seconds', '1800', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_news_patterns', '[]', 'content', 'JSON array of regex strings (case-insensitive). When non-empty, TopicDiscovery uses these patterns to reject titles as news/junk/merch/etc. instead of the hardcoded Glad Labs set (lawsuit/court, election/senator, shirt/merch, etc.). Empty array falls back to the hardcoded set for backwards compatibility. Customers running Poindexter for a niche where those topics are on-brand (real estate, fashion, politics) should set this to their own array — including ''[]'' to disable regex-based junk filtering entirely. Only the regex-based filter is overridden; the too-short-title guard still applies unconditionally.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_queue_low_threshold', '999', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_rejection_streak', '999', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_stale_hours', '8760', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_streak_window_hours', '6', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_style_distribution', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
