INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('uptime_kuma_admin_username', 'admin', 'monitoring', 'Kuma admin username (set by scripts/kuma_bootstrap.py)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('use_ollama', 'false', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('use_prefect_orchestration', 'true', 'orchestration', 'Prefect orchestration cutover flag (#410 Stage 4 complete 2026-05-16). Permanently true — services/task_executor.py was deleted; Prefect''s content_generation_flow is the sole dispatch path. Setting this to ''false'' has no effect; the row is kept so historical migrations remain idempotent. See docs/architecture/prefect-cutover.md for the full cutover history.', false, true) ON CONFLICT (key) DO NOTHING;
