INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('video_scene_model', 'llama3:latest', 'model_roles', 'Ollama model used to generate video scene descriptions from article text', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('video_server_url', 'http://host.docker.internal:9837', 'general', 'Video generation server', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('video_slideshow_prompt_model', 'ollama/llama3:latest', 'llm_routing', 'Per-call-site backstop for services.video_service SDXL prompt-gen. Deliberately non-thinking — qwen3/glm-4 thinking variants return empty on this prompt shape (Lane B batch 2 sweep).', false, true) ON CONFLICT (key) DO NOTHING;
