INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_brain', 'ollama', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_brain_mode', 'ollama', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_claude_code_enabled', 'true', 'voice', 'Master on/off for the claude-code voice room container (#1006). false/0/no/off = the container exits 0 and docker leaves it stopped under unless-stopped.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_claude_code_host_brain_url', 'http://host.docker.internal:8123/turn', 'voice', 'Host-brain daemon URL for the voice room (#1006), e.g. http://host.docker.internal:8123/turn. Empty = run claude in-container (local mode). Set to run turns on the host with full repo/git/write/MCP.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_claude_code_identity', 'claude-code-bot', 'voice', 'Participant identity for the claude-code voice bot (#1006). Distinct from the poindexter bot so both can coexist.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_claude_code_room_name', 'claude-code', 'voice', 'LiveKit room the claude-code voice bot joins (#1006). Must match an allowed room in routes/voice_routes.py so /voice/join?room= can reach it.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_claude_code_session_id', '287e7fc4-5147-4bf4-92b5-c3df15d25aa6', 'voice', 'Pinned claude -p voice session for the always-on claude-code room (#1006)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_claude_code_session_max_age_seconds', '14400', 'voice', 'Rotate the pinned claude -p voice session once it is older than this many seconds (#1006). 14400 = 4h.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_claude_code_session_token_budget', '200000', 'voice', 'Rotate the pinned claude -p voice session once cumulative input+output tokens exceed this (#1006).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_claude_code_transcript_enabled', 'true', 'voice', 'Master on/off for mirroring claude-code voice turns to Discord (#1006). false/0/no/off disables the mirror.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_claude_code_tts_voice', 'bf_isabella', 'voice', 'Kokoro voice id for the claude-code voice room only (#1006). Empty = fall back to the shared voice_agent_tts_voice. Lets the dev room run a distinct voice (e.g. bf_isabella) while the public poindexter room keeps its voice (e.g. bf_emma).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_identity', 'poindexter-bot', 'general', 'Bot identity inside the LiveKit room. Multiple bots in one room need distinct identities. Defaults to ''poindexter-bot'' so the human attendee is always the named participant.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_livekit_enabled', 'true', 'general', 'Toggle for the always-on voice-agent-livekit container. ''true'' (default) keeps the bot joined to the configured room. Set to ''false'' to take the LiveKit surface offline without editing docker-compose.local.yml — the container reads this at startup and exits 0 if disabled, then docker leaves it stopped under the unless-stopped restart policy.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_livekit_url', 'ws://livekit:7880', 'general', 'WebSocket URL the in-network voice bot uses to reach the LiveKit SFU. ''livekit'' is the docker-compose service name; override to ws(s)://<host>:<port> for a remote LiveKit instance. Voice clients (phone, browser) reach the SFU at http(s)://<host>:7880 — that URL is for the human, not the bot.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_llm_model', 'glm-4.7-5090:latest', 'general', 'Ollama model tag the voice agent uses for its LLM step. Same daily-driver as pipeline_writer_model by default.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_ollama_url', 'http://host.docker.internal:11434/v1', 'general', 'Ollama base URL. Default targets the host''s Ollama from inside Docker; running voice_agent.py directly on the host can stay on this URL or switch to http://localhost:11434.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_public_join_url', '', 'voice', 'Public URL the operator (or Claude, via the start_voice_call MCP tool) taps to join the always-on LiveKit voice room. Set via `poindexter settings set voice_agent_public_join_url <url>` after deployment. Read by the start_voice_call MCP tool — kept DB-backed so each operator configures their own host rather than inheriting a hardcoded URL.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_recall_k', '3', 'general', 'Top-K most-similar prior voice_messages turns to inject into the qwen3:8b system prompt as ''recalled context'' on each user turn. Separate from the linear last-N memory already shown in the prompt — recall surfaces older turns the user is referring back to. Default 3 keeps the prompt token count modest (voice replies stay snappy). Slice 3 of the voice-agent rollout — see Glad-Labs/poindexter#390.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_recall_min_similarity', '0.5', 'general', 'Cosine-similarity floor for voice_messages recall. Hits below this threshold are filtered out before the top-K cut, so a thin/empty conversation history doesn''t drag in unrelated noise. 0.5 is the same default used by the search-memory skill against the main embeddings table. Slice 3 of the voice-agent rollout — see Glad-Labs/poindexter#390.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_room_name', 'poindexter', 'general', 'LiveKit room the always-on voice-agent-livekit container joins on boot. Operator clients (https://meet.livekit.io, mobile LiveKit apps) join the same room name to talk to the bot. Change at runtime; container picks up on next restart.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_stt_base_url', 'http://speaches:8000/v1', 'voice', 'Speaches STT endpoint (OpenAI-compatible) used when voice_agent_stt_mode=sidecar. Compose service name on the shared poindexter network.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_stt_mode', 'sidecar', 'voice', 'STT backend for the voice pipeline (#1088): ''sidecar'' = thin client of the warm Speaches container; ''inprocess'' = load faster-whisper in-process (legacy). No silent default — an invalid value fails loud at pipeline build.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_stt_model', 'Systran/faster-whisper-medium', 'voice', 'faster-whisper model id passed to Speaches when voice_agent_stt_mode=sidecar. NOTE: an HF id, not the Pipecat Whisper enum used by the in-process voice_agent_whisper_model.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_system_prompt', 'You are Emma, a concise voice assistant for Matt at Glad Labs. Speak naturally — your output goes through text-to-speech, so avoid markdown, bullet lists, and code blocks. Use short sentences (under 30s of speech / ~80 words) unless Matt asks for more.
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_tts_base_url', 'http://speaches:8000/v1', 'voice', 'Speaches TTS endpoint used when voice_agent_tts_mode=sidecar. Same Speaches service as STT by default; separate key so STT and TTS can be split onto different hosts later without a migration.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_tts_mode', 'sidecar', 'voice', 'TTS backend for the voice pipeline (#1088): ''sidecar'' = thin client of the warm Speaches container; ''inprocess'' = run Kokoro in-process (legacy). No silent default.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_tts_model', 'speaches-ai/Kokoro-82M-v1.0-ONNX', 'voice', 'Kokoro model id passed to Speaches when voice_agent_tts_mode=sidecar. The voice id (bf_emma / bf_isabella) still comes from voice_agent_tts_voice / voice_agent_claude_code_tts_voice — those carry over unchanged because the voice pack is identical.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_tts_speed', '1.0', 'general', 'Kokoro playback speed multiplier. 1.0 = natural; 0.95 = slightly slower (helpful for technical content); 1.1 = brisker.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_tts_voice', 'bf_emma', 'general', 'Kokoro voice id. bf_emma is the top-graded British female in the Kokoro-82M catalog (B-). Other UK female options: bf_isabella (C), bf_alice (D), bf_lily (D).', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_user_speech_timeout', '1.3', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_vad_stop_secs', '0.4', 'general', 'Silero VAD end-of-speech silence window in seconds. Lower = snappier turn-taking but more risk of cutting the user off mid-sentence; higher = more tolerance for natural pauses. 0.2 matches Pipecat''s default. 0.15 for brisk dialog; 0.4 for thoughtful pauses.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_whisper_model', 'medium', 'voice_agent', 'faster-whisper model size. tiny/base/small/medium/large-v3. medium is the sweet spot for real voice accuracy on a 5090.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_bridge_chunk_max_chars', '500', 'voice', 'Maximum characters per TTS chunk emitted by voice_speak. Long replies are split at sentence boundaries so the operator can interrupt mid-reply — 500 chars is ~30 seconds of natural speech, matching the bridge''s empty-room grace window. Lower this if Kokoro stutters on long inputs; raise it (up to ~2000) for monologue-style replies where interruption is rare.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_bridge_enabled', 'true', 'voice', 'Master switch for the LiveKit MCP bridge — the architecturally-correct alternative to the subprocess-spawn voice_agent_brain_mode=claude-code path. When true (default), voice_join_room spins up a per-session bridge worker that lets the live Claude Code session claim voice in/out for itself. When false, voice_join_room returns a structured error pointing the operator at this key (no silent fallback per feedback_no_silent_defaults). The always-on voice-agent-livekit container is unaffected by this setting — it has its own voice_agent_livekit_enabled toggle.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_bridge_max_session_seconds', '1800', 'voice', 'Hard upper bound on a single bridge session, in seconds. The worker auto-leaves the LiveKit room after this many seconds regardless of activity. Defaults to 1800 (30 minutes) — long enough for a real dev pairing session, short enough that an orphaned bridge doesn''t squat on the room forever if the slash command crashes without calling voice_leave_room.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_bridge_stt_model', 'base.en', 'voice', 'faster-whisper model id loaded by the future Pipecat audio plane in the bridge worker. Defaults to base.en (CPU-friendly ~140 MB) so the public Poindexter release works on hardware without a GPU. Operators with a 5090 can flip to large-v3 for accuracy at higher VRAM cost.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_bridge_tts_voice', 'bf_isabella', 'voice', 'Kokoro voice id used by the bridge worker''s TTS path. Matches the always-on voice-agent-livekit container default so the operator''s auditory mental model stays consistent across the two surfaces — no jarring voice switch when flipping from ollama-Emma to claude-via-bridge.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_default_room', 'poindexter', 'voice', 'Default LiveKit room name when voice_join_room is called without an explicit channel_id. Distinct from voice_agent_room_name (the always-on ollama agent''s room) so the bridge and the agent don''t accidentally collide on the same room. Operators on custom deployments override at runtime: `poindexter settings set voice_default_room ops`.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('wan_server_url', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('webhook_freshness_revenue_threshold_days', '90', 'general', '', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('webhook_freshness_subscriber_threshold_days', '7', 'monitoring', 'Notify operator if no row has been added to subscriber_events in this many days. Default 7 because Resend should see at least one digest send weekly once newsletters are running. Loosen if the newsletter cadence is monthly.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('worker_heartbeat_interval_seconds', '30', 'pipeline', 'Worker heartbeat cadence. While processing a single task the Prefect content_generation_flow stamps pipeline_tasks.updated_at = NOW() every N seconds so the stale-task sweep can tell a live worker apart from a crashed one. Lower = faster failure detection; higher = less DB chatter. Must stay well below ``stale_task_timeout_minutes * 60``.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_context_snippet_max_chars', '500', 'writer_rag', 'Per-snippet character cap when building the snippet block for generate_with_context and generate_with_outline (the two helpers used by all writer RAG modes). Default 500 matches the prior hardcoded slice (s[''snippet''][:500]) in ai_content_generator.py. Higher = richer per-snippet context inside the writer prompt; lower = tighter prompt to fit more snippets / leave room for instructions.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_research_topic_max_sources', '2', 'writer_rag', 'Default max_sources for the module-level research_topic() shim used by the TWO_PASS writer mode. Default 2 matches the prior hardcoded default. Note: per the docstring on research_topic, this value is currently advisory — ResearchService.build_context caps internally (5 web results, 8 references). When that internal cap is plumbed through, this setting becomes the actual cap.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_two_pass_max_revision_loops', '3', 'writer_rag', 'Hard cap on revise → detect_needs → research_each → revise loops in the TWO_PASS LangGraph state machine. Default 3 matches the prior _MAX_REVISION_LOOPS module constant. Higher = give the writer more chances to fill [EXTERNAL_NEEDED:...] markers but increased risk of runaway / cost; lower = fail-fast on persistent gaps.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_two_pass_research_max_sources', '2', 'writer_rag', 'max_sources passed to research_topic for each [EXTERNAL_NEEDED: ...] marker the TWO_PASS draft surfaces. Default 2 matches the prior hardcoded literal in two_pass._research_each. Higher = more thorough research per gap, slower revise loop; lower = faster but flimsier external augmentation.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_two_pass_snippet_limit', '20', 'writer_rag', 'Top-N pgvector snippets fetched up-front in the TWO_PASS internal-first draft. Default 20 matches the prior hardcoded LIMIT 20 in _embed_and_fetch_snippets. Largest of the four writer modes by design — TWO_PASS needs a broad internal context base before the conditional external-augment loop kicks in. Higher = stronger internal grounding, longer initial prompt; lower = skinnier first draft, more reliance on the external research pass.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writing_style_reference', '', 'content', 'Operator-specific writing style traits injected into content-generation prompts. Set via `poindexter settings set writing_style_reference <description>` with a description of the desired voice and style.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writing_styles', '[{"name": "technical", "voice": "precise, detailed, code examples, show-dont-tell", "audience": "developers and engineers", "tone_notes": "confident but not arrogant, practical over theoretical", "enabled": true}, {"name": "founder", "voice": "casual first-person, lessons learned, conversational storytelling", "audience": "indie hackers and solo founders", "tone_notes": "authentic, vulnerable about failures, action-oriented", "enabled": true}, {"name": "explainer", "voice": "ELI5, heavy use of analogies, no jargon, build intuition", "audience": "beginners and non-technical readers", "tone_notes": "patient, encouraging, never condescending", "enabled": true}, {"name": "opinion", "voice": "strong takes, contrarian positions, backed by data", "audience": "senior devs and CTOs", "tone_notes": "provocative but fair, acknowledge counterarguments", "enabled": false}]', 'content', 'Configurable writing styles for content generation. Same pattern as image_styles.', false, true) ON CONFLICT (key) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('c7bde483-660e-4c2f-9188-f4b29dd066e5', 'programmatic_validator', 'qa', 100, 'programmatic_validator', true, true, '"{}"'::jsonb, '"{\"description\": \"Anti-hallucination regex + heuristic checks. Catches fabricated people, fake stats, invented quotes. Always-on safety net.\", \"legacy_setting_key\": null, \"seeded_by_migration\": \"0094\", \"legacy_setting_value_at_seed\": null}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('0b4b8419-75f0-443c-a6c8-06154fb36c47', 'citation_verifier', 'qa', 150, 'citation_verifier', false, true, '"{}"'::jsonb, '"{\"description\": \"Dead-link / minimum-citation gate — HTTP-HEAD-checks every external URL and scores the dead-link ratio (qa_citation_* settings). Restored from the #355-dropped review() step 1b (Glad-Labs/poindexter#659). Distinct from url_verifier. Advisory-first: scores but does not veto until graduated.\", \"legacy_setting_key\": \"qa_citation_verify_enabled\", \"seeded_by_migration\": \"20260603_070000\"}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('551643c0-65c8-4ddf-83c5-6ad5d02e6a60', 'llm_critic', 'qa', 200, 'llm_critic', true, true, '"{}"'::jsonb, '"{\"description\": \"Cross-model review by a different LLM than the writer. Style, logic, coherence, suspiciously specific claims.\", \"legacy_setting_key\": null, \"seeded_by_migration\": \"0094\", \"legacy_setting_value_at_seed\": null}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('a3c12978-bf9c-493f-9f03-0d2a3454846d', 'url_verifier', 'qa', 300, 'url_verifier', false, true, '"{}"'::jsonb, '"{\"description\": \"HEAD-checks every external URL in the content. Dead links block publish; healthy citations earn a small score bonus.\", \"legacy_setting_key\": null, \"seeded_by_migration\": \"0094\", \"legacy_setting_value_at_seed\": null}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('4b39682e-c724-4556-96b7-cf38908000b7', 'consistency', 'qa', 400, 'consistency', false, true, '"{}"'::jsonb, '"{\"description\": \"Internal-consistency gate — catches sections that contradict each other. Advisory unless score is unambiguously low.\", \"legacy_setting_key\": null, \"seeded_by_migration\": \"0094\", \"legacy_setting_value_at_seed\": null}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('a5c150c6-6a71-4c2b-b891-e2dac59ab06c', 'topic_delivery', 'qa', 410, 'topic_delivery', false, true, '"{}"'::jsonb, '"{\"description\": \"Bait-and-switch topic-delivery gate — does the body deliver what the title/topic promised? Restored from the #355-dropped review() step 2b (Glad-Labs/poindexter#658). Advisory-first: scores but does not veto until graduated to required_to_pass=true.\", \"legacy_setting_key\": null, \"seeded_by_migration\": \"20260603_070000\"}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('de37b591-6a63-430e-b94d-988fcc82272b', 'web_factcheck', 'qa', 500, 'web_factcheck', false, true, '"{}"'::jsonb, '"{\"description\": \"DuckDuckGo lookup for product/spec claims that the LLM critic cannot verify (training-cutoff override). Advisory.\", \"legacy_setting_key\": \"qa_web_factcheck_enabled\", \"seeded_by_migration\": \"0094\", \"legacy_setting_value_at_seed\": null}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('81df452a-c368-4592-bd10-9c533ed08246', 'vision_gate', 'qa', 600, 'vision_gate', false, true, '"{}"'::jsonb, '"{\"description\": \"Vision-model inline-image relevance check. Catches the ''stock photo of a server room on a FastAPI post'' pattern.\", \"legacy_setting_key\": \"qa_vision_check_enabled\", \"seeded_by_migration\": \"0094\", \"legacy_setting_value_at_seed\": \"true\"}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('714d51a3-cbc6-4664-affa-b2570344a623', 'deepeval_brand_fabrication', 'qa', 700, 'deepeval_brand_fabrication', false, true, '"{}"'::jsonb, '"{\"epic\": \"glad-labs-stack#329\", \"scaffold\": \"services/deepeval_rails.py\", \"description\": \"DeepEval BrandFabricationMetric — wraps content_validator fabrication patterns as a DeepEval BaseMetric. Advisory.\", \"seeded_by_migration\": \"20260508_215727\"}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('3c90a701-2408-46bb-a80a-301f89ff7d19', 'deepeval_g_eval', 'qa', 750, 'deepeval_g_eval', false, true, '"{}"'::jsonb, '"{\"epic\": \"glad-labs-stack#329\", \"scaffold\": \"services/deepeval_rails.py\", \"description\": \"DeepEval g-eval (LLM-judge): grades the post against deepeval_g_eval_criterion using a chain-of-thought evaluation. Advisory.\", \"seeded_by_migration\": \"20260510_022034\"}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('21d6f71d-fd72-4ad0-bd8a-7acadb849755', 'deepeval_faithfulness', 'qa', 760, 'deepeval_faithfulness', false, true, '"{}"'::jsonb, '"{\"epic\": \"glad-labs-stack#329\", \"scaffold\": \"services/deepeval_rails.py\", \"description\": \"DeepEval FaithfulnessMetric: every claim in the post must be attributable to a chunk of the research bundle the writer was given. Skipped when there is no research context. Advisory.\", \"seeded_by_migration\": \"20260510_022034\"}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('dce61a9d-b8da-420e-a4c6-240b54b69f89', 'guardrails_brand', 'qa', 770, 'guardrails_brand', false, true, '"{}"'::jsonb, '"{\"epic\": \"glad-labs-stack#329\", \"scaffold\": \"services/guardrails_rails.py\", \"description\": \"guardrails-ai brand-fabrication validator: same regex patterns as content_validator but routed through guardrails-ai''s Validator/Guard framework. Cross-framework signal alongside the DeepEval brand rail. Advisory.\", \"seeded_by_migration\": \"20260510_030530\"}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('0646090d-34ea-444e-b28c-d30559a3a588', 'guardrails_competitor', 'qa', 780, 'guardrails_competitor', false, true, '"{}"'::jsonb, '"{\"epic\": \"glad-labs-stack#329\", \"scaffold\": \"services/guardrails_rails.py\", \"description\": \"guardrails-ai competitor-mention validator: flags when any name in app_settings.guardrails_competitor_list appears in the post body. Skipped entirely when the list is empty. Advisory.\", \"seeded_by_migration\": \"20260510_030530\"}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata) VALUES ('b319b928-0689-4542-9bde-3f19541172ff', 'ragas_eval', 'qa', 790, 'ragas_eval', false, true, '"{}"'::jsonb, '"{\"epic\": \"glad-labs-stack#329\", \"scaffold\": \"services/ragas_eval.py\", \"description\": \"Ragas RAG-quality reviewer: faithfulness + answer_relevancy + context_precision averaged into one score. Disabled by default because each call is ~6K judge tokens. Advisory when enabled.\", \"seeded_by_migration\": \"20260510_032959\"}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('6cf4f7ff-955b-42ae-b72d-8a800e739cdf', 'banned_header', true, 'warning', '"{}"'::jsonb, NULL, 'Detects generic section headings (''## Introduction'', ''## Conclusion'', ''## Summary'', etc.). Score-penalty only.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('afad17ad-456b-4fa4-9391-ae3fda264ef5', 'brand_contradiction', true, 'warning', '"{}"'::jsonb, NULL, 'Detects content promoting paid cloud APIs (''OpenAI pricing'', ''pay per token to Anthropic''). Brand-specific to local-first Ollama positioning.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('e3cb5109-9785-4959-aa59-3978299d8fc6', 'code_block_density', true, 'warning', '"{\"min_line_ratio_pct\": 20, \"min_blocks_per_700w\": 1, \"long_post_floor_words\": 300}"'::jsonb, NULL, 'Warns when tech-tagged posts ship without enough fenced code blocks. Tag list comes from `code_density_tag_filter`. Soft signal — never critical. Disabled via `code_density_check_enabled` OR by setting this row''s `enabled=false`.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('32eaaba6-e4d0-49bc-af1f-a85a9ff97f83', 'fabricated_experience', true, 'error', '"{}"'::jsonb, NULL, 'Detects AI pretending to be a person (''I was on a call with ...'', ''a client of mine ...''). Critical fail.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('908ce4b7-59d6-4774-ae1c-4c71edc75562', 'fake_person', true, 'error', '"{}"'::jsonb, NULL, 'Detects fabricated person names + titles (''Sarah Smith, CEO at ...''). Critical — fabricated humans are a publishing-blocker fail.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('c6a0a23f-282f-4ced-a695-2b65bcc8401c', 'fake_quote', true, 'error', '"{}"'::jsonb, NULL, 'Detects fabricated quotes attributed to named people. Critical fail — same class of lie as fake stats.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('28f12989-aaa7-4fc2-86d9-c854291c6470', 'fake_stat', true, 'error', '"{}"'::jsonb, NULL, 'Detects fabricated statistics (''43% reduction'', ''McKinsey study found ...'') without citation backing. Critical fail per Matt 2026-04-11.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('cbab4145-8559-4168-b996-6250b1ecaf3d', 'filler_intro', true, 'warning', '"{}"'::jsonb, NULL, 'Detects ''In this post/article/guide/tutorial'' opening lines in the first 500 chars. Score-penalty only.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('fa73db81-67c3-48b1-a78d-7a11a2ecdca0', 'filler_phrase', true, 'warning', '"{}"'::jsonb, NULL, 'Detects LLM filler phrases (''many organizations have found'', ''the landscape is constantly evolving'', ''in today''s fast-paced world''). Score-penalty only.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('b3cd2c5d-9b91-464d-a5ae-c99b23b7795f', 'first_person_claims', true, 'warning', '"{\"max_penalty\": 3.0, \"penalty_per\": 1.0}"'::jsonb, NULL, 'Penalises ''I/we built/created/...'' phrasing in the post body. Bypassed for niches in `qa_allow_first_person_niches` (CSV) for backwards compatibility with PR #160. Tune `applies_to_niches` to scope this rule to specific niches.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('073ec17a-37eb-4145-a534-b9a4de8e9cfc', 'glad_labs_claim', true, 'error', '"{}"'::jsonb, NULL, 'Detects impossible claims about the company (decade-long history, thousands of employees, named clients) — uses configured `company_name` + `company_age_months` settings.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('c33a1d4a-8596-4f1b-8630-825233d59e09', 'hallucinated_link', true, 'error', '"{}"'::jsonb, NULL, 'Detects ''see our guide on X'' phrasing that points at internal content that doesn''t exist. Critical fail.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('ddc2c1f7-ba60-4585-bc50-7df5e7f2c82c', 'hallucinated_reference', true, 'warning', '"{}"'::jsonb, NULL, 'Detects backtick-quoted library/API references that don''t match Python stdlib, top-500 PyPI, or known Ollama models. Also flags topic-orthogonal library mentions (CadQuery in an ai-ml post).') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('e4fcee03-1b6f-4145-a836-8b989a136aaa', 'image_placeholder', true, 'error', '"{}"'::jsonb, NULL, 'Detects [IMAGE-1: ...], [FIGURE: ...], [DIAGRAM: ...] placeholder tokens that the image pipeline failed to replace. Critical — these leak into the rendered post and look broken.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('55c9934e-5201-4780-9633-73946f816a45', 'known_wrong_fact', true, 'error', '"{}"'::jsonb, NULL, 'Detects facts overridden via the `fact_overrides` DB table. Severity is set per-row in fact_overrides, but this rule must be enabled for the override gate to fire at all.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('84442c57-56ff-48da-9e51-c4085b5465ca', 'late_acronym_expansion', true, 'warning', '"{\"min_prior_uses\": 2}"'::jsonb, NULL, 'Detects acronyms expanded after they''ve already been used 2+ times unexpanded (''use the CRM ... CRM (Customer Relationship Management)'').') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('17ac0be6-ca77-4eec-a612-bebc668e4b72', 'leaked_image_prompt', true, 'warning', '"{}"'::jsonb, NULL, 'Detects image-generation prompts left inline in the markdown after image rendering (''*A split-screen comparison of ...*'').') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('c6fccec1-f6be-4313-8c63-0b67406fa955', 'meta_commentary', true, 'warning', '"{\"max_penalty\": 2.0, \"penalty_per\": 0.5}"'::jsonb, NULL, 'Penalises ''in this post'', ''we''ll explore'', ''this article discusses'' and similar self-referential phrasing in the body.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('250e1868-699a-4db4-b96a-2a4a990106e2', 'title_diversity', true, 'warning', '"{}"'::jsonb, NULL, 'Detects titles starting with overused openers (''Beyond the ...'', ''Unlocking ...'', ''The Ultimate Guide to ...''). Score-penalty only.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('4d918005-fd67-4a4a-850a-11632618ab53', 'title_year_claim', true, 'error', '"{}"'::jsonb, NULL, 'Detects titles claiming multi-year history (''Five Years of ...'', ''10 Years Building ...'') that contradict configured `company_age_months`.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('42f43432-3261-4656-95b2-22fe78c7aece', 'truncated_content', true, 'error', '"{}"'::jsonb, NULL, 'Detects content that ends mid-sentence — strong signal the LLM hit its output token limit. Critical — readers get an incomplete article.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('2493522b-5fa7-4015-a193-b4140dd7d2c5', 'unlinked_citation', true, 'warning', '"{\"warning_reject_threshold\": 3}"'::jsonb, NULL, 'Detects ''introduced in <Paper Title>'', ''according to <Source>'', ''arXiv:2401.12345'' without an accompanying URL. Promoted to critical when the matched text names a source type (Medium, article, paper, study) without a URL within ~100 chars.') ON CONFLICT (id) DO NOTHING;
INSERT INTO content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description) VALUES ('d67d37d7-da0c-46c0-ac5a-20abdae3193f', 'unresolved_placeholder', true, 'error', '"{}"'::jsonb, NULL, 'Detects unresolved internal-link placeholders left in post bodies — [posts/<uuid>], [posts/{slug}], bare [posts/abc-123] without a (/posts/abc-123) URL, and [POST_ID: ...] variants. These leak when the writer hints at the link shape but internal_link_coherence''s resolution step never converts them to real Markdown links. Critical — readers see broken brackets in the rendered post.') ON CONFLICT (id) DO NOTHING;
