INSERT INTO niches (id, slug, name, active, target_audience_tags, writer_prompt_override, batch_size, discovery_cadence_minute_floor, default_media_to_generate, default_template_slug) VALUES ('919124f3-22de-4133-812c-88bde6975318', 'glad-labs', 'Glad Labs', true, ARRAY['indie-devs','ai-curious','prospects','future-matt']::text[], 'You are writing a blog post for Glad Labs — an AI-operated content
INSERT INTO pipeline_templates (slug, name, description, version, active, graph_def, created_by) VALUES ('canonical_blog', 'Canonical Blog', 'Atom-composed canonical_blog pipeline (#355)', 6, true, '"{\"name\": \"canonical_blog\", \"edges\": [{\"to\": \"generate_content\", \"from\": \"verify_task\"}, {\"to\": \"writer_self_review\", \"from\": \"generate_content\"}, {\"to\": \"resolve_internal_link_placeholders\", \"from\": \"writer_self_review\"}, {\"to\": \"quality_evaluation\", \"from\": \"resolve_internal_link_placeholders\"}, {\"to\": \"url_validation\", \"from\": \"quality_evaluation\"}, {\"to\": \"replace_inline_images\", \"from\": \"url_validation\"}, {\"to\": \"source_featured_image\", \"from\": \"replace_inline_images\"}, {\"to\": \"caption_images\", \"from\": \"source_featured_image\"}, {\"to\": \"qa_programmatic\", \"from\": \"caption_images\"}, {\"to\": \"qa_critic\", \"from\": \"qa_programmatic\"}, {\"to\": \"qa_deepeval\", \"from\": \"qa_critic\"}, {\"to\": \"qa_guardrails\", \"from\": \"qa_deepeval\"}, {\"to\": \"qa_ragas\", \"from\": \"qa_guardrails\"}, {\"to\": \"qa_vision\", \"from\": \"qa_ragas\"}, {\"to\": \"qa_topic_delivery\", \"from\": \"qa_vision\"}, {\"to\": \"qa_citations\", \"from\": \"qa_topic_delivery\"}, {\"to\": \"qa_consistency\", \"from\": \"qa_citations\"}, {\"to\": \"qa_web_factcheck\", \"from\": \"qa_consistency\"}, {\"to\": \"qa_aggregate\", \"from\": \"qa_web_factcheck\"}, {\"to\": \"seo_title\", \"from\": \"qa_aggregate\"}, {\"to\": \"seo_description\", \"from\": \"seo_title\"}, {\"to\": \"seo_keywords\", \"from\": \"seo_description\"}, {\"to\": \"generate_media_scripts\", \"from\": \"seo_keywords\"}, {\"to\": \"generate_video_shot_list\", \"from\": \"generate_media_scripts\"}, {\"to\": \"capture_training_data\", \"from\": \"generate_video_shot_list\"}, {\"to\": \"finalize_task\", \"from\": \"capture_training_data\"}, {\"to\": \"END\", \"from\": \"finalize_task\"}], \"entry\": \"verify_task\", \"nodes\": [{\"id\": \"verify_task\", \"atom\": \"stage.verify_task\"}, {\"id\": \"generate_content\", \"atom\": \"stage.generate_content\"}, {\"id\": \"writer_self_review\", \"atom\": \"stage.writer_self_review\"}, {\"id\": \"resolve_internal_link_placeholders\", \"atom\": \"stage.resolve_internal_link_placeholders\"}, {\"id\": \"quality_evaluation\", \"atom\": \"stage.quality_evaluation\"}, {\"id\": \"url_validation\", \"atom\": \"stage.url_validation\"}, {\"id\": \"replace_inline_images\", \"atom\": \"stage.replace_inline_images\"}, {\"id\": \"source_featured_image\", \"atom\": \"stage.source_featured_image\"}, {\"id\": \"caption_images\", \"atom\": \"stage.caption_images\"}, {\"id\": \"qa_programmatic\", \"atom\": \"qa.programmatic\"}, {\"id\": \"qa_critic\", \"atom\": \"qa.critic\"}, {\"id\": \"qa_deepeval\", \"atom\": \"qa.deepeval\"}, {\"id\": \"qa_guardrails\", \"atom\": \"qa.guardrails\"}, {\"id\": \"qa_ragas\", \"atom\": \"qa.ragas\"}, {\"id\": \"qa_vision\", \"atom\": \"qa.vision\"}, {\"id\": \"qa_topic_delivery\", \"atom\": \"qa.topic_delivery\"}, {\"id\": \"qa_citations\", \"atom\": \"qa.citations\"}, {\"id\": \"qa_consistency\", \"atom\": \"qa.consistency\"}, {\"id\": \"qa_web_factcheck\", \"atom\": \"qa.web_factcheck\"}, {\"id\": \"qa_aggregate\", \"atom\": \"qa.aggregate\"}, {\"id\": \"seo_title\", \"atom\": \"seo.generate_title\"}, {\"id\": \"seo_description\", \"atom\": \"seo.generate_description\"}, {\"id\": \"seo_keywords\", \"atom\": \"seo.extract_keywords\"}, {\"id\": \"generate_media_scripts\", \"atom\": \"stage.generate_media_scripts\"}, {\"id\": \"generate_video_shot_list\", \"atom\": \"stage.generate_video_shot_list\"}, {\"id\": \"capture_training_data\", \"atom\": \"stage.capture_training_data\"}, {\"id\": \"finalize_task\", \"atom\": \"stage.finalize_task\"}], \"description\": \"Canonical blog pipeline (atom-composed): coarse stages + the qa.* rail block (replacing cross_model_qa) + the seo.* atom chain (replacing generate_seo_metadata).\"}"'::jsonb, 'factory') ON CONFLICT (slug) DO UPDATE SET graph_def = EXCLUDED.graph_def, version = EXCLUDED.version, active = EXCLUDED.active, updated_at = now();
INSERT INTO pipeline_templates (slug, name, description, version, active, graph_def, created_by) VALUES ('content_publishing_pipeline', 'content_publishing_pipeline', 'Generates content, performs cross-model QA, creates SEO metadata, and finalizes the task.', 1, true, '"{\"name\": \"content_publishing_pipeline\", \"edges\": [{\"to\": \"generate_content\", \"from\": \"verify_task\"}, {\"to\": \"cross_model_qa\", \"from\": \"generate_content\"}, {\"to\": \"generate_seo_metadata\", \"from\": \"cross_model_qa\"}, {\"to\": \"finalize_task\", \"from\": \"generate_seo_metadata\"}, {\"to\": \"END\", \"from\": \"finalize_task\"}], \"entry\": \"verify_task\", \"nodes\": [{\"id\": \"verify_task\", \"atom\": \"stage.verify_task\"}, {\"id\": \"generate_content\", \"atom\": \"stage.generate_content\"}, {\"id\": \"cross_model_qa\", \"atom\": \"stage.cross_model_qa\"}, {\"id\": \"generate_seo_metadata\", \"atom\": \"stage.generate_seo_metadata\"}, {\"id\": \"finalize_task\", \"atom\": \"stage.finalize_task\"}], \"description\": \"Generates content, performs cross-model QA, creates SEO metadata, and finalizes the task.\"}"'::jsonb, 'architect_llm') ON CONFLICT (slug) DO UPDATE SET graph_def = EXCLUDED.graph_def, version = EXCLUDED.version, active = EXCLUDED.active, updated_at = now();
INSERT INTO pipeline_templates (slug, name, description, version, active, graph_def, created_by) VALUES ('daily_dev_diary', 'daily_dev_diary', 'Generates a daily dev diary post by narrating the context bundle into prose.', 1, true, '"{\"name\": \"daily_dev_diary\", \"edges\": [{\"to\": \"END\", \"from\": \"narrate_context\"}], \"entry\": \"narrate_context\", \"nodes\": [{\"id\": \"narrate_context\", \"atom\": \"atoms.narrate_bundle\"}], \"description\": \"Generates a daily dev diary post by narrating the context bundle into prose.\"}"'::jsonb, 'architect_llm') ON CONFLICT (slug) DO UPDATE SET graph_def = EXCLUDED.graph_def, version = EXCLUDED.version, active = EXCLUDED.active, updated_at = now();
INSERT INTO pipeline_templates (slug, name, description, version, active, graph_def, created_by) VALUES ('daily_dev_diary_with_approval', 'daily_dev_diary_with_approval', 'Narrates the daily dev bundle and pauses execution for operator review before termination.', 1, true, '"{\"name\": \"daily_dev_diary_with_approval\", \"edges\": [{\"to\": \"operator_review\", \"from\": \"narrate_diary\"}, {\"to\": \"END\", \"from\": \"operator_review\"}], \"entry\": \"narrate_diary\", \"nodes\": [{\"id\": \"narrate_diary\", \"atom\": \"atoms.narrate_bundle\", \"config\": {\"task_id\": \"daily_task_001\", \"context_bundle\": {\"merged_prs\": [], \"notable_commits\": []}}}, {\"id\": \"operator_review\", \"atom\": \"atoms.approval_gate\", \"config\": {\"task_id\": \"daily_task_001\", \"gate_name\": \"dev_diary_review\", \"site_config\": {\"environment\": \"production\"}, \"database_service\": \"default_db_service\"}}], \"description\": \"Narrates the daily dev bundle and pauses execution for operator review before termination.\"}"'::jsonb, 'architect_llm') ON CONFLICT (slug) DO UPDATE SET graph_def = EXCLUDED.graph_def, version = EXCLUDED.version, active = EXCLUDED.active, updated_at = now();
INSERT INTO pipeline_templates (slug, name, description, version, active, graph_def, created_by) VALUES ('dev_diary', 'Dev Diary', 'Atom-composed dev_diary pipeline (#355 follow-through)', 2, true, '"{\"name\": \"dev_diary\", \"edges\": [{\"to\": \"narrate_bundle\", \"from\": \"verify_task\"}, {\"to\": \"source_featured_image\", \"from\": \"narrate_bundle\"}, {\"to\": \"finalize_task\", \"from\": \"source_featured_image\"}, {\"to\": \"END\", \"from\": \"finalize_task\"}], \"entry\": \"verify_task\", \"nodes\": [{\"id\": \"verify_task\", \"atom\": \"stage.verify_task\"}, {\"id\": \"narrate_bundle\", \"atom\": \"atoms.narrate_bundle\"}, {\"id\": \"source_featured_image\", \"atom\": \"stage.source_featured_image\"}, {\"id\": \"finalize_task\", \"atom\": \"stage.finalize_task\"}], \"description\": \"dev_diary pipeline (atom-composed): verify_task -> narrate_bundle (single-call narrative writer) -> source_featured_image -> finalize_task. Mirrors the retired legacy factory; no QA/SEO rails by design (status-report artifact).\"}"'::jsonb, 'factory') ON CONFLICT (slug) DO UPDATE SET graph_def = EXCLUDED.graph_def, version = EXCLUDED.version, active = EXCLUDED.active, updated_at = now();
INSERT INTO pipeline_templates (slug, name, description, version, active, graph_def, created_by) VALUES ('dev_diary_compose', 'dev_diary_compose', 'Composes a dev diary entry by narrating the provided context bundle into prose.', 1, true, '"{\"name\": \"dev_diary_compose\", \"edges\": [{\"to\": \"END\", \"from\": \"compose_diary\"}], \"entry\": \"compose_diary\", \"nodes\": [{\"id\": \"compose_diary\", \"atom\": \"atoms.narrate_bundle\"}], \"description\": \"Composes a dev diary entry by narrating the provided context bundle into prose.\"}"'::jsonb, 'architect_llm') ON CONFLICT (slug) DO UPDATE SET graph_def = EXCLUDED.graph_def, version = EXCLUDED.version, active = EXCLUDED.active, updated_at = now();
INSERT INTO pipeline_templates (slug, name, description, version, active, graph_def, created_by) VALUES ('dev_diary_prose', 'dev_diary_prose', 'Narrates the dev diary bundle into prose output.', 1, true, '"{\"name\": \"dev_diary_prose\", \"edges\": [{\"to\": \"END\", \"from\": \"start_narrate\"}], \"entry\": \"start_narrate\", \"nodes\": [{\"id\": \"start_narrate\", \"atom\": \"atoms.narrate_bundle\", \"config\": {}}], \"description\": \"Narrates the dev diary bundle into prose output.\"}"'::jsonb, 'architect_llm') ON CONFLICT (slug) DO UPDATE SET graph_def = EXCLUDED.graph_def, version = EXCLUDED.version, active = EXCLUDED.active, updated_at = now();
INSERT INTO pipeline_templates (slug, name, description, version, active, graph_def, created_by) VALUES ('dev_diary_quality_check', 'dev_diary_quality_check', 'Narrates a dev diary bundle, reviews it with two critics, aggregates the reviews, and routes to operator approval.', 1, true, '"{\"name\": \"dev_diary_quality_check\", \"edges\": [{\"to\": \"critic_1\", \"from\": \"narrate_step\"}, {\"to\": \"critic_2\", \"from\": \"narrate_step\"}, {\"to\": \"aggregate_reviews\", \"from\": \"critic_1\"}, {\"to\": \"aggregate_reviews\", \"from\": \"critic_2\"}, {\"to\": \"final_gate\", \"from\": \"aggregate_reviews\"}], \"entry\": \"narrate_step\", \"nodes\": [{\"id\": \"narrate_step\", \"atom\": \"atoms.narrate_bundle\", \"config\": {\"context_bundle\": {}}}, {\"id\": \"critic_1\", \"atom\": \"atoms.review_with_critic\"}, {\"id\": \"critic_2\", \"atom\": \"atoms.review_with_critic\"}, {\"id\": \"aggregate_reviews\", \"atom\": \"atoms.aggregate_reviews\"}, {\"id\": \"final_gate\", \"atom\": \"atoms.approval_gate\", \"config\": {\"task_id\": \"dev_diary_001\", \"gate_name\": \"final_approval\"}}], \"description\": \"Narrates a dev diary bundle, reviews it with two critics, aggregates the reviews, and routes to operator approval.\"}"'::jsonb, 'architect_llm') ON CONFLICT (slug) DO UPDATE SET graph_def = EXCLUDED.graph_def, version = EXCLUDED.version, active = EXCLUDED.active, updated_at = now();
INSERT INTO pipeline_templates (slug, name, description, version, active, graph_def, created_by) VALUES ('dev_diary_quality_pipeline', 'dev_diary_quality_pipeline', 'A quality-gated dev diary pipeline that narrates content, validates it, runs parallel critics, aggregates reviews, and requires operator approval.', 1, true, '"{\"name\": \"dev_diary_quality_pipeline\", \"edges\": [{\"to\": \"narrate\", \"from\": \"verify_task\"}, {\"to\": \"validators\", \"from\": \"narrate\"}, {\"to\": \"critic_a\", \"from\": \"validators\"}, {\"to\": \"critic_b\", \"from\": \"validators\"}, {\"to\": \"aggregate\", \"from\": \"critic_a\"}, {\"to\": \"aggregate\", \"from\": \"critic_b\"}, {\"to\": \"approval_gate\", \"from\": \"aggregate\"}, {\"to\": \"finalize\", \"from\": \"approval_gate\"}], \"entry\": \"verify_task\", \"nodes\": [{\"id\": \"verify_task\", \"atom\": \"stage.verify_task\"}, {\"id\": \"narrate\", \"atom\": \"atoms.narrate_bundle\"}, {\"id\": \"validators\", \"atom\": \"atoms.run_validators\", \"config\": {\"halt_on_critical\": true}}, {\"id\": \"critic_a\", \"atom\": \"atoms.review_with_critic\", \"config\": {\"critic_role\": \"Technical Reviewer\"}}, {\"id\": \"critic_b\", \"atom\": \"atoms.review_with_critic\", \"config\": {\"critic_role\": \"Style Editor\"}}, {\"id\": \"aggregate\", \"atom\": \"atoms.aggregate_reviews\"}, {\"id\": \"approval_gate\", \"atom\": \"atoms.approval_gate\", \"config\": {\"gate_name\": \"Dev Diary Review\"}}, {\"id\": \"finalize\", \"atom\": \"stage.finalize_task\"}], \"description\": \"A quality-gated dev diary pipeline that narrates content, validates it, runs parallel critics, aggregates reviews, and requires operator approval.\"}"'::jsonb, 'architect_llm') ON CONFLICT (slug) DO UPDATE SET graph_def = EXCLUDED.graph_def, version = EXCLUDED.version, active = EXCLUDED.active, updated_at = now();
