INSERT INTO retention_policies (id, name, handler_name, table_name, filter_sql, age_column, ttl_days, downsample_rule, summarize_handler, enabled, config, metadata) VALUES ('ca8f8825-b37b-48b6-b983-0ca6e302bb00', 'gpu_metrics', 'downsample', 'gpu_metrics', NULL, 'timestamp', NULL, '"{\"group_by\": [], \"aggregations\": [{\"as\": \"avg_utilization\", \"fn\": \"avg\", \"col\": \"utilization\"}, {\"as\": \"peak_utilization\", \"fn\": \"max\", \"col\": \"utilization\"}, {\"as\": \"avg_temperature\", \"fn\": \"avg\", \"col\": \"temperature\"}, {\"as\": \"peak_temperature\", \"fn\": \"max\", \"col\": \"temperature\"}, {\"as\": \"avg_power_draw\", \"fn\": \"avg\", \"col\": \"power_draw\"}, {\"as\": \"peak_power_draw\", \"fn\": \"max\", \"col\": \"power_draw\"}, {\"as\": \"avg_memory_used\", \"fn\": \"avg\", \"col\": \"memory_used\"}, {\"as\": \"peak_memory_used\", \"fn\": \"max\", \"col\": \"memory_used\"}, {\"as\": \"avg_fan_speed\", \"fn\": \"avg\", \"col\": \"fan_speed\"}], \"rollup_table\": \"gpu_metrics_hourly\", \"keep_raw_days\": 30, \"rollup_interval\": \"1 hour\"}"'::jsonb, NULL, true, '"{}"'::jsonb, '"{\"description\": \"GPU utilization rollup — keeps 30d raw + hourly beyond\", \"precondition\": \"rollup_table gpu_metrics_hourly must exist — see handler doc\"}"'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO fact_overrides (id, pattern, correct_fact, category, severity, active) VALUES (2, '(?:24\s*GB|24GB|24\s*gigabytes)(?:\s+of)?\s+(?:VRAM|video\s+memory|GDDR\w*)[^.]{0,80}?(?:RTX\s*)?5090', 'RTX 5090 has 32GB VRAM, not 24GB (a pre-release leak number the model remembers from training data).', 'hardware', 'critical', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO fact_overrides (id, pattern, correct_fact, category, severity, active) VALUES (1, '(?:RTX\s*)?5090[^.]{0,80}?(?:24\s*GB|24GB|24\s*gigabytes)(?!\s*(?:/|per|plus))', 'RTX 5090 has 32GB VRAM, not 24GB (a pre-release leak number the model remembers from training data).', 'hardware', 'critical', true) ON CONFLICT (id) DO NOTHING;
